export interface Medicine {
  id?: number;
  visualId: string; // ITM-001 format
  name: string;
  barcode: string;
  price: number;
  costPrice: number;
  stock: number;
  category: string;
  expiryDate: string;
  supplierId?: number;
  salesCount?: number;
}

export interface Supplier {
  id?: number;
  name: string;
  phone: string;
  totalSuppliedValue: number;
}

export interface Customer {
  id?: number;
  name: string;
  phone: string;
  totalDebt: number;
}

export type PaymentMethod = 'cash' | 'bank' | 'credit' | 'split';

export interface Sale {
  id?: number;
  totalAmount: number;
  totalCost: number;
  discountAmount: number;
  netAmount: number;
  cashAmount: number;
  bankakAmount: number;
  bankakTrxId?: string;
  debtAmount: number;
  customerId?: number;
  timestamp: number;
  itemsJson: string; // List of {name, price, costPrice, quantity}
  paymentMethod: PaymentMethod;
}

export interface CartItem {
  medicine: Medicine;
  quantity: number;
}

export type ViewType = 'pos' | 'accounting';

import { Dexie, type Table } from 'dexie';
import { Medicine, Sale, Supplier, Customer } from './types';

export class PharmacyDB extends Dexie {
  medicines!: Table<Medicine, number>;
  sales!: Table<Sale, number>;
  suppliers!: Table<Supplier, number>;
  customers!: Table<Customer, number>;

  constructor() {
    super('PharmacyDB');

    this.version(4).stores({
      medicines: '++id, visualId, name, barcode, stock, expiryDate, category, salesCount, supplierId',
      sales: '++id, timestamp, customerId, paymentMethod',
      suppliers: '++id, name, phone',
      customers: '++id, name, phone, totalDebt'
    });
  }
}

export const db = new PharmacyDB();

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { 
  Search, Plus, Package, BarChart3, ShoppingCart, X, Trash2, 
  CheckCircle2, History, TrendingUp, AlertCircle, Filter, 
  Calendar, Tag, Coins, CreditCard, Wallet, UserMinus, 
  ChevronLeft, Printer, ShoppingBag, ArrowRight, Minus, Edit3,
  Users, Truck, Landmark, Receipt, ArrowDownRight, UserPlus
} from 'lucide-react';
import { db } from './db';
import { Medicine, ViewType, Sale, CartItem, PaymentMethod, Supplier, Customer } from './types';

const formatDate = (date: string) => new Date(date).toLocaleDateString('ar-EG', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const formatTime = (ts: number) => new Date(ts).toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' });

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('pos');
  const [accountingSubView, setAccountingSubView] = useState<'sales' | 'inventory' | 'finance'>('sales');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [salesHistory, setSalesHistory] = useState<Sale[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);

  const [searchQuery, setSearchQuery] = useState('');
  const [cart, setCart] = useState<Map<number, CartItem>>(new Map<number, CartItem>());
  const [activeCategory, setActiveCategory] = useState<string>('الكل');
  const [quickEditId, setQuickEditId] = useState<number | null>(null);

  const [isEditOpen, setIsEditOpen] = useState(false);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const [checkoutResult, setCheckoutResult] = useState<{status: 'success' | 'error', msg: string, saleId?: number} | null>(null);

  const [categoryStats, setCategoryStats] = useState<Record<string, number>>(() => {
    const saved = localStorage.getItem('raha_cat_stats');
    return saved ? JSON.parse(saved) : {};
  });

  const [invCategoryFilter, setInvCategoryFilter] = useState<string>('all');
  const [invSupplierFilter, setInvSupplierFilter] = useState<string>('all');
  const [salesDateFilter, setSalesDateFilter] = useState<string>(new Date().toISOString().split('T')[0]);

  const searchInputRef = useRef<HTMLInputElement>(null);

  const loadData = useCallback(async () => {
    const [allMeds, allSales, allSupps, allCusts] = await Promise.all([
      db.medicines.toArray(),
      db.sales.orderBy('timestamp').reverse().toArray(),
      db.suppliers.toArray(),
      db.customers.toArray()
    ]);
    setMedicines(allMeds);
    setSalesHistory(allSales);
    setSuppliers(allSupps);
    setCustomers(allCusts);
  }, []);

  useEffect(() => {
    loadData();
    if (searchInputRef.current) searchInputRef.current.focus();
  }, [loadData]);

  const addToCart = (med: Medicine) => {
    if (med.id === undefined) return;
    if (med.stock <= 0) {
      setCheckoutResult({status: 'error', msg: 'هذا الصنف غير متوفر حالياً'});
      setTimeout(() => setCheckoutResult(null), 2000);
      return;
    }
    const newCart = new Map<number, CartItem>(cart);
    const existing = newCart.get(med.id);
    const currentQty = existing?.quantity || 0;

    if (currentQty >= med.stock) {
        setCheckoutResult({status: 'error', msg: 'تم الوصول للحد الأقصى للمخزون'});
        setTimeout(() => setCheckoutResult(null), 2000);
        return;
    }
    newCart.set(med.id, { medicine: med, quantity: currentQty + 1 });
    setCart(newCart);
    if (navigator.vibrate) navigator.vibrate([20]);
  };

  const removeFromCart = (id: number) => {
    const newCart = new Map<number, CartItem>(cart);
    const item = newCart.get(id);
    if (item && item.quantity > 1) {
      newCart.set(id, { ...item, quantity: item.quantity - 1 });
    } else {
      newCart.delete(id);
    }
    setCart(newCart);
  };

  const handlePrint = (saleId?: number) => {
    alert(`جاري محاكاة طباعة الفاتورة رقم: ${saleId || 'جديدة'}`);
  };

  const filteredInventory = useMemo(() => {
    return medicines.filter(m => {
      const matchesCat = invCategoryFilter === 'all' || m.category === invCategoryFilter;
      const matchesSupp = invSupplierFilter === 'all' || m.supplierId?.toString() === invSupplierFilter;
      return matchesCat && matchesSupp;
    });
  }, [medicines, invCategoryFilter, invSupplierFilter]);

  const capitalStats = useMemo(() => {
    const totalCapital = filteredInventory.reduce((sum, m) => sum + (m.costPrice * m.stock), 0);
    const itemTypeCount = filteredInventory.length;
    return { totalCapital, itemTypeCount };
  }, [filteredInventory]);

  const filteredSales = useMemo(() => {
    return salesHistory.filter(s => {
      const sDate = new Date(s.timestamp).toISOString().split('T')[0];
      return !salesDateFilter || sDate === salesDateFilter;
    });
  }, [salesHistory, salesDateFilter]);

  const categories = useMemo(() => {
    const uniqueCats = Array.from(new Set(medicines.map(m => m.category || 'عام')));
    return uniqueCats.sort((a, b) => (categoryStats[b] || 0) - (categoryStats[a] || 0));
  }, [medicines, categoryStats]);

  const handleCategorySelect = (cat: string) => {
    setActiveCategory(cat);
    if (cat !== 'الكل') {
      const newStats = { ...categoryStats, [cat]: (categoryStats[cat] || 0) + 1 };
      setCategoryStats(newStats);
      localStorage.setItem('raha_cat_stats', JSON.stringify(newStats));
    }
  };

  const medicinesForPOS = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    let filtered = medicines.filter(m => 
      (m.name.toLowerCase().includes(q) || m.barcode.toLowerCase().includes(q) || m.visualId.toLowerCase().includes(q)) &&
      (activeCategory === 'الكل' || m.category === activeCategory)
    );
    return filtered.sort((a, b) => (b.salesCount || 0) - (a.salesCount || 0));
  }, [medicines, searchQuery, activeCategory]);

  const handleSaveMedicine = async (data: Medicine) => {
    if (data.id) {
      await db.medicines.update(data.id, data);
    } else {
      // Auto-generate Visual ID
      const count = await db.medicines.count();
      const visualId = `ITM-${(count + 1).toString().padStart(3, '0')}`;
      await db.medicines.add({ ...data, visualId });
    }
    setIsEditOpen(false); setEditingMedicine(null); loadData();
  };

  const handleQuickPriceUpdate = async (id: number, field: 'price' | 'costPrice', val: string) => {
    const num = parseFloat(val);
    if (!isNaN(num)) {
      await db.medicines.update(id, { [field]: num });
      loadData();
    }
  };

  const cartItemsArr: CartItem[] = Array.from(cart.values());
  const cartTotal = cartItemsArr.reduce((sum, item: CartItem) => sum + (item.medicine.price * item.quantity), 0);

  return (
    <div className="flex flex-col h-screen bg-[#F8FAFC] text-slate-900 overflow-hidden">
      <header className="bg-white px-6 pt-8 pb-4 shadow-[0_4px_20px_-5px_rgba(0,0,0,0.05)] z-20 shrink-0 border-b border-slate-100">
        <div className="flex justify-between items-center mb-6">
            <div>
                <h1 className="text-2xl font-black text-emerald-600 tracking-tight">صيدلية راحة</h1>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">النسخة المالية الاحترافية</p>
            </div>
            <div className="flex gap-2">
                <div className="w-10 h-10 rounded-2xl bg-emerald-50 flex items-center justify-center text-emerald-600">
                    <ShoppingBag size={20} />
                </div>
            </div>
        </div>
        <div className="relative group mb-4">
          <input 
            ref={searchInputRef} 
            type="text" 
            placeholder="ابحث عن دواء أو كود (ITM-001)..." 
            className="w-full bg-slate-50 text-slate-900 rounded-[22px] py-4 pr-14 pl-6 text-lg font-bold border-2 border-transparent focus:border-emerald-500 focus:bg-white transition-all shadow-sm outline-none" 
            value={searchQuery} 
            onChange={(e) => setSearchQuery(e.target.value)} 
          />
          <Search className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-emerald-500 transition-colors" size={24} />
          {searchQuery && (
            <button onClick={() => setSearchQuery('')} className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 hover:text-slate-500">
                <X size={20} />
            </button>
          )}
        </div>

        {view === 'pos' && (
          <div className="flex flex-row-reverse gap-2 overflow-x-auto no-scrollbar pb-2">
            <button 
              onClick={() => handleCategorySelect('الكل')}
              className={`px-6 py-2.5 rounded-2xl text-xs font-black whitespace-nowrap transition-all ${activeCategory === 'الكل' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400'}`}
            >
              الكل
            </button>
            {categories.map(cat => (
              <button 
                key={cat}
                onClick={() => handleCategorySelect(cat)}
                className={`px-6 py-2.5 rounded-2xl text-xs font-black whitespace-nowrap transition-all ${activeCategory === cat ? 'bg-emerald-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400'}`}
              >
                {cat}
              </button>
            ))}
          </div>
        )}
      </header>

      <main className="flex-grow overflow-y-auto p-4 pb-48 no-scrollbar">
        {view === 'pos' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            {medicinesForPOS.map((med) => (
              <div 
                key={med.id} 
                onContextMenu={(e) => { e.preventDefault(); setEditingMedicine(med); setIsEditOpen(true); }}
                className={`group relative bg-white p-5 rounded-[28px] flex justify-between items-center transition-all shadow-[0_2px_10px_rgba(0,0,0,0.02)] border-2 ${cart.has(med.id!) ? 'border-emerald-500 bg-emerald-50/30' : 'border-transparent hover:border-slate-100'}`}
              >
                <div className="flex-grow" onClick={() => addToCart(med)}>
                  <div className="flex items-center gap-2 mb-1">
                    <span className="text-[10px] font-black text-slate-300">{med.visualId}</span>
                    <h3 className="font-bold text-lg text-slate-800 leading-tight">{med.name}</h3>
                    {cart.has(med.id!) && (
                      <span className="bg-emerald-600 text-white text-[10px] px-2 py-0.5 rounded-full font-black animate-in zoom-in">
                        {cart.get(med.id!)?.quantity}
                      </span>
                    )}
                  </div>
                  <div className="flex items-center gap-3">
                    <span className="text-[10px] font-bold text-slate-400 bg-slate-100 px-2 py-0.5 rounded-md uppercase tracking-tighter">{med.category}</span>
                    <span className={`text-[10px] font-black ${med.stock < 10 ? 'text-rose-500' : 'text-emerald-600'}`}>
                        {med.stock <= 0 ? 'نفذ' : `متاح: ${med.stock}`}
                    </span>
                  </div>
                  {cart.has(med.id!) && (
                    <div className="flex items-center gap-4 mt-3 animate-in fade-in" onClick={e => e.stopPropagation()}>
                      <button onClick={() => removeFromCart(med.id!)} className="w-8 h-8 rounded-xl bg-rose-50 text-rose-500 flex items-center justify-center active:scale-90 transition-all"><Minus size={16}/></button>
                      <span className="font-black text-slate-700 text-sm">{cart.get(med.id!)?.quantity}</span>
                      <button onClick={() => addToCart(med)} className="w-8 h-8 rounded-xl bg-emerald-600 text-white flex items-center justify-center active:scale-90 transition-all"><Plus size={16}/></button>
                    </div>
                  )}
                </div>

                <div className="text-left flex flex-col items-end gap-2">
                  <div className="relative group/price">
                    {quickEditId === med.id ? (
                      <div className="flex flex-col gap-2 animate-in zoom-in duration-200">
                        <input type="number" className="w-20 bg-emerald-50 text-emerald-700 text-center font-black rounded-lg border-b-2 border-emerald-500 py-1 outline-none text-sm" defaultValue={med.price} onBlur={(e) => handleQuickPriceUpdate(med.id!, 'price', e.target.value)} onKeyDown={e => e.key === 'Enter' && setQuickEditId(null)} onClick={e => e.stopPropagation()}/>
                      </div>
                    ) : (
                      <div className="cursor-pointer" onClick={(e) => { e.stopPropagation(); setQuickEditId(med.id!); }}>
                        <div className="text-xl font-black text-emerald-700">{med.price.toFixed(2)}</div>
                        <div className="text-[9px] font-black text-slate-300 uppercase">جنيهاً</div>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="space-y-4 animate-in fade-in duration-500">
            <div className="flex bg-white/80 backdrop-blur-md p-1.5 rounded-3xl shadow-sm border border-slate-100 sticky top-0 z-10 overflow-x-auto no-scrollbar">
              <button onClick={() => setAccountingSubView('sales')} className={`flex-1 min-w-[100px] flex items-center justify-center gap-2 py-3 rounded-[20px] text-sm font-bold transition-all ${accountingSubView === 'sales' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}> <History size={16} /> المبيعات </button>
              <button onClick={() => setAccountingSubView('inventory')} className={`flex-1 min-w-[100px] flex items-center justify-center gap-2 py-3 rounded-[20px] text-sm font-bold transition-all ${accountingSubView === 'inventory' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}> <Package size={16} /> المخزون </button>
              <button onClick={() => setAccountingSubView('finance')} className={`flex-1 min-w-[100px] flex items-center justify-center gap-2 py-3 rounded-[20px] text-sm font-bold transition-all ${accountingSubView === 'finance' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}> <Landmark size={16} /> المالية </button>
            </div>

            {accountingSubView === 'sales' && (
              <div className="space-y-4">
                <input type="date" className="bg-white p-4 rounded-3xl font-bold text-sm shadow-sm border border-slate-100 w-full" value={salesDateFilter} onChange={e => setSalesDateFilter(e.target.value)} />
                <div className="space-y-3">
                    {filteredSales.map(sale => (
                        <div key={sale.id} className="bg-white p-5 rounded-[28px] border border-slate-100 flex flex-col gap-3">
                            <div className="flex justify-between items-start">
                                <div>
                                    <div className="text-lg font-black text-slate-800">{sale.netAmount.toFixed(2)} ج.م</div>
                                    <div className="text-[10px] text-slate-400 font-bold flex gap-2">
                                      <span>{formatTime(sale.timestamp)}</span>
                                      <span className={`px-2 rounded-full ${sale.paymentMethod === 'split' ? 'bg-amber-100 text-amber-600' : 'bg-emerald-100 text-emerald-600'}`}>
                                        {sale.paymentMethod === 'split' ? 'دفع مركب' : 'نقدي'}
                                      </span>
                                    </div>
                                </div>
                                <button onClick={() => handlePrint(sale.id)} className="p-2 bg-slate-50 text-slate-400 rounded-xl"> <Printer size={18} /> </button>
                            </div>
                        </div>
                    ))}
                </div>
              </div>
            )}

            {accountingSubView === 'inventory' && (
              <div className="space-y-4">
                <div className="bg-white p-5 rounded-[32px] border border-slate-100 grid grid-cols-2 gap-3">
                   <select className="bg-slate-50 p-3 rounded-2xl font-bold text-xs" value={invCategoryFilter} onChange={e => setInvCategoryFilter(e.target.value)}>
                      <option value="all">كل الفئات</option>
                      {categories.map(c => <option key={c} value={c}>{c}</option>)}
                   </select>
                   <select className="bg-slate-50 p-3 rounded-2xl font-bold text-xs" value={invSupplierFilter} onChange={e => setInvSupplierFilter(e.target.value)}>
                      <option value="all">كل الموردين</option>
                      {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                   </select>
                </div>
                <div className="grid grid-cols-1 gap-3">
                  {filteredInventory.map(med => (
                    <div key={med.id} onClick={() => { setEditingMedicine(med); setIsEditOpen(true); }} className="bg-white p-5 rounded-[28px] flex justify-between items-center shadow-sm border border-slate-100">
                      <div className="flex items-center gap-4">
                          <div className="w-10 h-10 rounded-2xl bg-emerald-50 text-emerald-500 flex items-center justify-center"> <Package size={20} /> </div>
                          <div>
                              <div className="font-bold text-slate-800">{med.name}</div>
                              <div className="text-[10px] text-slate-400">{med.visualId} | {med.category}</div>
                          </div>
                      </div>
                      <div className="text-left">
                        <div className="text-lg font-black">{med.stock}</div>
                        <div className="text-[8px] font-bold text-slate-300">قطعة</div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {accountingSubView === 'finance' && (
              <div className="space-y-6">
                <div className="bg-emerald-600 p-8 rounded-[40px] text-white shadow-2xl shadow-emerald-200">
                    <TrendingUp size={24} className="mb-4 opacity-70" />
                    <div className="text-4xl font-black">{capitalStats.totalCapital.toLocaleString()} <span className="text-sm font-normal opacity-50">ج.م</span></div>
                    <div className="text-[12px] font-bold opacity-70 mt-2 uppercase tracking-widest">إجمالي رأس المال المحبوس في المخزون</div>
                    <div className="flex gap-4 mt-6">
                        <div className="bg-white/10 px-4 py-2 rounded-2xl border border-white/10">
                            <div className="text-xl font-bold">{capitalStats.itemTypeCount}</div>
                            <div className="text-[10px] opacity-60">نوع صنف</div>
                        </div>
                    </div>
                </div>

                <div className="space-y-4">
                    <h2 className="text-xl font-black text-slate-800 mr-2 flex items-center gap-2"> <Users size={20} className="text-emerald-600"/> ديون العملاء</h2>
                    <div className="grid grid-cols-1 gap-3">
                        {customers.filter(c => c.totalDebt > 0).map(customer => (
                            <div key={customer.id} className="bg-white p-5 rounded-[28px] border border-slate-100 flex justify-between items-center">
                                <div>
                                    <div className="font-bold text-slate-800">{customer.name}</div>
                                    <div className="text-[10px] text-slate-400">{customer.phone}</div>
                                </div>
                                <div className="text-left">
                                    <div className="text-lg font-black text-rose-500">{customer.totalDebt.toFixed(2)}</div>
                                    <div className="text-[8px] font-bold text-slate-300 uppercase">مستحق</div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      {view === 'pos' && cart.size > 0 && (
        <div className="fixed bottom-28 left-0 right-0 px-6 z-50 animate-in slide-in-from-bottom duration-500">
            <div className="max-w-xl mx-auto bg-slate-900/90 backdrop-blur-xl text-white p-6 rounded-[35px] shadow-2xl border border-white/10">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <button onClick={() => setCart(new Map())} className="w-12 h-12 rounded-2xl bg-white/10 flex items-center justify-center text-rose-400 active:scale-90 transition-all"><Trash2 size={22} /></button>
                        <div>
                            <div className="text-2xl font-black tabular-nums">{cartTotal.toFixed(2)} <span className="text-[10px] font-normal opacity-50">ج.م</span></div>
                            <div className="text-[10px] font-bold text-emerald-400">{cartItemsArr.reduce((s, i) => s + i.quantity, 0)} أصناف مختارة</div>
                        </div>
                    </div>
                    <button onClick={() => setIsCheckoutOpen(true)} className="bg-emerald-500 hover:bg-emerald-400 text-white px-8 py-4 rounded-[24px] font-black text-lg shadow-xl active:scale-95 transition-all flex items-center gap-2">
                      متابعة الدفع <ArrowRight size={20} />
                    </button>
                </div>
            </div>
        </div>
      )}

      {isCheckoutOpen && (
        <CheckoutModal 
            cartTotal={cartTotal} 
            items={cartItemsArr}
            customers={customers}
            onClose={() => setIsCheckoutOpen(false)}
            onSuccess={(res) => {
              setCart(new Map());
              setIsCheckoutOpen(false);
              setCheckoutResult(res);
              loadData();
              setTimeout(() => setCheckoutResult(null), 4000);
            }}
        />
      )}

      {checkoutResult && (
        <div className={`fixed top-8 left-6 right-6 z-[100] p-5 rounded-[28px] shadow-2xl flex items-center justify-between animate-in slide-in-from-top-10 duration-500 ${checkoutResult.status === 'success' ? 'bg-emerald-600 text-white' : 'bg-rose-600 text-white'}`}>
          <div className="flex items-center gap-3">
            {checkoutResult.status === 'success' ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
            <span className="font-black">{checkoutResult.msg}</span>
          </div>
        </div>
      )}

      <nav className="bg-white/80 backdrop-blur-xl border-t border-slate-100 flex justify-around items-center px-4 pt-4 pb-10 z-40 shrink-0">
        <button onClick={() => setView('pos')} className={`flex flex-col items-center gap-1.5 transition-all ${view === 'pos' ? 'text-emerald-600' : 'text-slate-300'}`}> 
            <ShoppingCart size={26} strokeWidth={view === 'pos' ? 3 : 2} /> <span className="text-[10px] font-black uppercase">البيع</span> 
        </button>
        <button onClick={() => { setEditingMedicine(null); setIsEditOpen(true); }} className="relative -mt-16 bg-emerald-600 text-white w-18 h-18 rounded-[28px] shadow-2xl flex items-center justify-center active:scale-90 transition-transform border-4 border-[#F8FAFC]">
            <Plus size={32} strokeWidth={3} />
        </button>
        <button onClick={() => setView('accounting')} className={`flex flex-col items-center gap-1.5 transition-all ${view === 'accounting' ? 'text-emerald-600' : 'text-slate-300'}`}> 
            <BarChart3 size={26} strokeWidth={view === 'accounting' ? 3 : 2} /> <span className="text-[10px] font-black uppercase">التقارير</span> 
        </button>
      </nav>

      {isEditOpen && (
        <MedicineDialog 
          categories={categories} 
          suppliers={suppliers}
          initialData={editingMedicine} 
          onSave={handleSaveMedicine} 
          onClose={() => setIsEditOpen(false)} 
          onDelete={async (id) => { if(confirm('حذف نهائي؟')) { await db.medicines.delete(id); setIsEditOpen(false); loadData(); } }} 
        />
      )}
    </div>
  );
};

const CheckoutModal: React.FC<{ cartTotal: number, items: CartItem[], customers: Customer[], onClose: () => void, onSuccess: (res: any) => void }> = ({ cartTotal, items, customers, onClose, onSuccess }) => {
  const [discount, setDiscount] = useState(0);
  const [cashAmount, setCashAmount] = useState(0);
  const [bankakEnabled, setBankakEnabled] = useState(false);
  const [bankakAmount, setBankakAmount] = useState(0);
  const [bankakTrxId, setBankakTrxId] = useState('');
  const [debtEnabled, setDebtEnabled] = useState(false);
  const [selectedCustomerId, setSelectedCustomerId] = useState<number | null>(null);
  const [newCustomerMode, setNewCustomerMode] = useState(false);
  const [newCustomerName, setNewCustomerName] = useState('');

  const netTotal = useMemo(() => Math.max(0, cartTotal - discount), [cartTotal, discount]);
  const amountPaid = useMemo(() => (cashAmount || 0) + (bankakEnabled ? (bankakAmount || 0) : 0), [cashAmount, bankakEnabled, bankakAmount]);
  const balance = useMemo(() => netTotal - amountPaid, [netTotal, amountPaid]);

  // Domino logic for Remaining/Debt
  const debtAmount = useMemo(() => (debtEnabled && balance > 0) ? balance : 0, [debtEnabled, balance]);
  const changeAmount = useMemo(() => (!debtEnabled && balance < 0) ? Math.abs(balance) : 0, [debtEnabled, balance]);

  const canCheckout = useMemo(() => {
    if (netTotal === 0) return true;
    if (balance > 0 && !debtEnabled) return false;
    if (debtEnabled && !selectedCustomerId && !newCustomerMode) return false;
    if (newCustomerMode && !newCustomerName) return false;
    if (bankakEnabled && !bankakTrxId) return false;
    return true;
  }, [netTotal, balance, debtEnabled, selectedCustomerId, newCustomerMode, newCustomerName, bankakEnabled, bankakTrxId]);

  const handleFinalize = async () => {
    try {
      let finalCustomerId = selectedCustomerId;
      if (newCustomerMode && newCustomerName) {
        finalCustomerId = await db.customers.add({ name: newCustomerName, phone: '', totalDebt: 0 });
      }

      await db.transaction('rw', ['medicines', 'sales', 'customers'], async () => {
        // Update Inventory
        for (const item of items) {
          const med = await db.medicines.get(item.medicine.id!);
          if (!med || med.stock < item.quantity) throw new Error(`نقص مخزون ${item.medicine.name}`);
          await db.medicines.update(item.medicine.id!, { 
            stock: med.stock - item.quantity,
            salesCount: (med.salesCount || 0) + item.quantity
          });
        }

        // Update Customer Debt
        if (debtAmount > 0 && finalCustomerId) {
          const cust = await db.customers.get(finalCustomerId);
          if (cust) await db.customers.update(finalCustomerId, { totalDebt: cust.totalDebt + debtAmount });
        }

        // Add Sale
        await db.sales.add({
          totalAmount: cartTotal,
          totalCost: items.reduce((s, i) => s + (i.medicine.costPrice * i.quantity), 0),
          discountAmount: discount,
          netAmount: netTotal,
          cashAmount,
          bankakAmount: bankakEnabled ? bankakAmount : 0,
          bankakTrxId,
          debtAmount,
          customerId: finalCustomerId || undefined,
          timestamp: Date.now(),
          itemsJson: JSON.stringify(items.map(i => ({ name: i.medicine.name, qty: i.quantity, price: i.medicine.price }))),
          paymentMethod: 'split'
        });
      });

      onSuccess({ status: 'success', msg: 'تمت العملية بنجاح' });
    } catch (err: any) {
      alert(err.message);
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-white w-full max-w-lg rounded-t-[40px] sm:rounded-[45px] overflow-hidden shadow-2xl flex flex-col max-h-[95vh] animate-in slide-in-from-bottom duration-300">
        <div className="px-8 pt-8 pb-4 flex justify-between items-center shrink-0">
          <h2 className="text-2xl font-black text-slate-800">إتمام العملية</h2>
          <button onClick={onClose} className="w-10 h-10 bg-slate-50 text-slate-400 rounded-2xl flex items-center justify-center"><X/></button>
        </div>

        <div className="px-8 pb-10 space-y-6 overflow-y-auto no-scrollbar">
          <div className="bg-slate-50 p-6 rounded-[32px] flex justify-between items-center">
              <div>
                  <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">المطلوب سداده</div>
                  <div className="text-3xl font-black text-emerald-600">{netTotal.toFixed(2)}</div>
              </div>
              <div className="text-left">
                  <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">إجمالي العربة</div>
                  <div className="text-xl font-bold text-slate-400 line-through">{cartTotal.toFixed(2)}</div>
              </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 mr-2 uppercase flex items-center gap-1"> <Tag size={10}/> الخصم </label>
                  <input type="number" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={discount} onChange={e => setDiscount(parseFloat(e.target.value) || 0)} />
              </div>
              <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 mr-2 uppercase flex items-center gap-1"> <Wallet size={10}/> النقدي </label>
                  <input type="number" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={cashAmount} onChange={e => setCashAmount(parseFloat(e.target.value) || 0)} />
              </div>
          </div>

          <div className={`p-5 rounded-[28px] border-2 transition-all ${bankakEnabled ? 'bg-blue-50 border-blue-200' : 'bg-slate-50 border-transparent'}`}>
             <div className="flex justify-between items-center mb-4">
                <div className="flex items-center gap-3">
                    <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${bankakEnabled ? 'bg-blue-500 text-white' : 'bg-slate-200 text-slate-400'}`}> <Landmark size={20}/> </div>
                    <span className="font-black text-sm">تحويل بنكك / فيزا</span>
                </div>
                <input type="checkbox" className="w-6 h-6 rounded-lg accent-blue-500" checked={bankakEnabled} onChange={e => setBankakEnabled(e.target.checked)} />
             </div>
             {bankakEnabled && (
               <div className="grid grid-cols-2 gap-3 animate-in zoom-in-95 duration-200">
                  <input type="number" placeholder="المبلغ" className="bg-white border-2 border-blue-100 rounded-xl p-3 font-bold text-sm outline-none" value={bankakAmount} onChange={e => setBankakAmount(parseFloat(e.target.value) || 0)} />
                  <input type="text" placeholder="رقم العملية (Trx ID)" className="bg-white border-2 border-blue-100 rounded-xl p-3 font-bold text-sm outline-none" value={bankakTrxId} onChange={e => setBankakTrxId(e.target.value)} />
               </div>
             )}
          </div>

          <div className={`p-5 rounded-[28px] border-2 transition-all ${debtEnabled ? 'bg-amber-50 border-amber-200' : 'bg-slate-50 border-transparent'}`}>
             <div className="flex justify-between items-center mb-4">
                <div className="flex items-center gap-3">
                    <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${debtEnabled ? 'bg-amber-500 text-white' : 'bg-slate-200 text-slate-400'}`}> <UserMinus size={20}/> </div>
                    <span className="font-black text-sm">تسجيل كـ دين (آجل)</span>
                </div>
                <input type="checkbox" className="w-6 h-6 rounded-lg accent-amber-500" checked={debtEnabled} onChange={e => setDebtEnabled(e.target.checked)} />
             </div>
             {debtEnabled && (
               <div className="space-y-3 animate-in zoom-in-95 duration-200">
                  <div className="flex gap-2">
                      {newCustomerMode ? (
                        <input type="text" placeholder="اسم العميل الجديد" className="flex-grow bg-white border-2 border-amber-100 rounded-xl p-3 font-bold text-sm outline-none" value={newCustomerName} onChange={e => setNewCustomerName(e.target.value)} />
                      ) : (
                        <select className="flex-grow bg-white border-2 border-amber-100 rounded-xl p-3 font-bold text-sm outline-none" value={selectedCustomerId || ''} onChange={e => setSelectedCustomerId(parseInt(e.target.value) || null)}>
                            <option value="">اختر عميل...</option>
                            {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                      )}
                      <button onClick={() => setNewCustomerMode(!newCustomerMode)} className="w-12 bg-white border-2 border-amber-100 rounded-xl flex items-center justify-center text-amber-500"> {newCustomerMode ? <X size={20}/> : <UserPlus size={20}/>} </button>
                  </div>
                  <div className="bg-amber-100/50 p-3 rounded-xl flex justify-between items-center">
                      <span className="text-[10px] font-black text-amber-700">سيتم ترحيل مبلغ:</span>
                      <span className="font-black text-amber-800">{debtAmount.toFixed(2)}</span>
                  </div>
               </div>
             )}
          </div>

          <div className="pt-4 border-t border-slate-100">
             <div className="flex justify-between items-center mb-6">
                <div>
                   <div className="text-[10px] font-black text-slate-400 uppercase">المتبقي / الفكة</div>
                   <div className={`text-2xl font-black ${balance > 0 ? 'text-rose-500' : 'text-blue-500'}`}>
                      {balance > 0 ? (debtEnabled ? '0.00' : `-${balance.toFixed(2)}`) : changeAmount.toFixed(2)}
                   </div>
                </div>
                <button 
                  disabled={!canCheckout}
                  onClick={handleFinalize}
                  className={`px-10 py-5 rounded-[28px] font-black text-lg shadow-xl transition-all flex items-center gap-2 ${canCheckout ? 'bg-emerald-600 text-white active:scale-95' : 'bg-slate-200 text-slate-400 cursor-not-allowed'}`}
                >
                    تأكيد العملية <CheckCircle2 size={24}/>
                </button>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

