import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { 
  Search, Plus, Package, BarChart3, ShoppingCart, X, Trash2, 
  CheckCircle2, History, TrendingUp, AlertCircle, Sparkles,
  Printer, ShoppingBag, ArrowRight, Minus, Users, Landmark, 
  Wallet, UserPlus, Info, MessageCircle, Send, BrainCircuit
} from 'lucide-react';
import { db } from './db';
import { Medicine, ViewType, Sale, CartItem, Supplier, Customer } from './types';
import { GoogleGenAI } from "@google/genai";

const formatTime = (ts: number) => new Date(ts).toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' });

const App: React.FC = () => {
  const [view, setView] = useState<ViewType | 'ai'>('pos');
  const [accountingSubView, setAccountingSubView] = useState<'sales' | 'inventory' | 'finance'>('sales');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [salesHistory, setSalesHistory] = useState<Sale[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);

  const [searchQuery, setSearchQuery] = useState('');
  const [cart, setCart] = useState<Map<number, CartItem>>(new Map());
  const [activeCategory, setActiveCategory] = useState('الكل');
  const [isEditOpen, setIsEditOpen] = useState(false);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const [checkoutResult, setCheckoutResult] = useState<{status: 'success' | 'error', msg: string} | null>(null);

  // AI State
  const [aiQuery, setAiQuery] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  const loadData = useCallback(async () => {
    const [allMeds, allSales, allSupps, allCusts] = await Promise.all([
      db.medicines.toArray(),
      db.sales.orderBy('timestamp').reverse().toArray(),
      db.suppliers.toArray(),
      db.customers.toArray()
    ]);
    setMedicines(allMeds);
    setSalesHistory(allSales);
    setSuppliers(allSupps);
    setCustomers(allCusts);
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const addToCart = (med: Medicine) => {
    if (med.id === undefined || med.stock <= 0) return;
    const newCart = new Map(cart);
    const existing = newCart.get(med.id);
    const qty = (existing?.quantity || 0) + 1;
    if (qty > med.stock) return;
    newCart.set(med.id, { medicine: med, quantity: qty });
    setCart(newCart);
  };

  const removeFromCart = (id: number) => {
    const newCart = new Map(cart);
    const item = newCart.get(id);
    if (item && item.quantity > 1) newCart.set(id, { ...item, quantity: item.quantity - 1 });
    else newCart.delete(id);
    setCart(newCart);
  };

  const categories = useMemo(() => ['الكل', ...Array.from(new Set(medicines.map(m => m.category || 'عام')))], [medicines]);

  const filteredMeds = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    return medicines.filter(m => 
      (m.name.toLowerCase().includes(q) || m.visualId.toLowerCase().includes(q)) &&
      (activeCategory === 'الكل' || m.category === activeCategory)
    ).sort((a, b) => (b.salesCount || 0) - (a.salesCount || 0));
  }, [medicines, searchQuery, activeCategory]);

  const stats = useMemo(() => {
    const totalCapital = medicines.reduce((s, m) => s + (m.costPrice * m.stock), 0);
    const todaySales = salesHistory.filter(s => new Date(s.timestamp).toDateString() === new Date().toDateString())
                                  .reduce((s, sa) => s + sa.netAmount, 0);
    const totalDebts = customers.reduce((s, c) => s + (c.totalDebt || 0), 0);
    return { totalCapital, todaySales, totalDebts };
  }, [medicines, salesHistory, customers]);

  const handleAiAnalysis = async () => {
    if (!aiQuery.trim()) return;
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const context = `
        بيانات الصيدلية الحالية:
        - إجمالي الأدوية: ${medicines.length}
        - قيمة المخزون: ${stats.totalCapital} جنيهاً
        - مبيعات اليوم: ${stats.todaySales} جنيهاً
        - ديون العملاء: ${stats.totalDebts} جنيهاً
        - أدوية منتهية الصلاحية قريباً: ${medicines.filter(m => new Date(m.expiryDate) < new Date(Date.now() + 90 * 24 * 60 * 60 * 1000)).map(m => m.name).join(', ')}
      `;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `${context}\nسؤال المستخدم: ${aiQuery}`,
        config: { systemInstruction: "أنت خبير إدارة صيدليات ذكي. أجب باللغة العربية بأسلوب مهني ومختصر." }
      });
      setAiResponse(response.text || 'عذراً، لم أستطع تحليل البيانات.');
    } catch (e) {
      setAiResponse('حدث خطأ أثناء الاتصال بالذكاء الاصطناعي.');
    } finally {
      setIsAiLoading(false);
    }
  };

  const cartTotal = Array.from(cart.values()).reduce((s, i) => s + (i.medicine.price * i.quantity), 0);

  return (
    <div className="flex flex-col h-screen bg-[#F8FAFC] overflow-hidden select-none">
      {/* Header */}
      <header className="bg-white px-6 pt-10 pb-6 shadow-sm z-30 border-b border-slate-100 shrink-0">
        <div className="flex justify-between items-center mb-6">
          <div>
            <h1 className="text-2xl font-black text-emerald-600 tracking-tight flex items-center gap-2">
              <ShoppingBag size={24} /> صيدلية راحة
            </h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">الذكاء الاصطناعي مفعّل</p>
          </div>
          <button onClick={() => setView('ai')} className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${view === 'ai' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-emerald-50 text-emerald-600'}`}>
            <BrainCircuit size={24} />
          </button>
        </div>

        {view === 'pos' && (
          <>
            <div className="relative mb-4">
              <input 
                type="text" 
                placeholder="ابحث عن دواء (الاسم أو الكود)..." 
                className="w-full bg-slate-50 rounded-2xl py-4 pr-12 pl-4 text-lg font-bold border-2 border-transparent focus:border-emerald-500 focus:bg-white outline-none transition-all shadow-sm"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <Search className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
            </div>
            <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
              {categories.map(cat => (
                <button 
