const CheckoutModal: React.FC<{ total: number, items: CartItem[], customers: Customer[], onClose: () => void, onSuccess: (res: any) => void }> = ({ total, items, customers, onClose, onSuccess }) => {
  const [cash, setCash] = useState(total);
  const [bank, setBank] = useState(0);
  const [isDebt, setIsDebt] = useState(false);
  const [selectedCust, setSelectedCust] = useState<number | null>(null);

  const balance = total - (cash + bank);

  const handleFinish = async () => {
    try {
      await db.transaction('rw', ['medicines', 'sales', 'customers'], async () => {
        for (const item of items) {
          const m = await db.medicines.get(item.medicine.id!);
          if (m) await db.medicines.update(m.id!, { stock: m.stock - item.quantity, salesCount: (m.salesCount || 0) + item.quantity });
        }
        if (isDebt && selectedCust && balance > 0) {
          const c = await db.customers.get(selectedCust);
          if (c) await db.customers.update(c.id!, { totalDebt: (c.totalDebt || 0) + balance });
        }
        await db.sales.add({
          totalAmount: total, netAmount: total, discountAmount: 0, cashAmount: cash, bankakAmount: bank, debtAmount: isDebt ? Math.max(0, balance) : 0,
          totalCost: items.reduce((s,i) => s + (i.medicine.costPrice * i.quantity), 0),
          timestamp: Date.now(), paymentMethod: 'split', itemsJson: JSON.stringify(items), customerId: selectedCust || undefined
        });
      });
      onSuccess({});
    } catch (e) { alert('فشلت العملية'); }
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4">
       <div className="bg-white w-full max-w-lg rounded-t-[40px] sm:rounded-[45px] shadow-2xl flex flex-col animate-slide-up">
          <div className="p-8 pb-4 flex justify-between items-center">
             <h2 className="text-2xl font-black text-slate-800">إتمام العملية</h2>
             <button onClick={onClose} className="w-10 h-10 bg-slate-50 text-slate-400 rounded-2xl flex items-center justify-center"><X/></button>
          </div>
          <div className="p-8 space-y-6">
             <div className="bg-slate-50 p-6 rounded-[32px] flex justify-between items-center">
                <div>
                  <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">المطلوب سداده</div>
                  <div className="text-3xl font-black text-emerald-600">{total.toFixed(2)}</div>
                </div>
                <div className="w-14 h-14 rounded-full bg-emerald-100 flex items-center justify-center text-emerald-600"><CheckCircle2 size={32}/></div>
             </div>

             <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 mr-2">كاش (نقدي)</label>
                  <input type="number" className="w-full bg-slate-50 rounded-2xl p-4 font-black outline-none border-2 border-emerald-500" value={cash} onChange={e => setCash(parseFloat(e.target.value) || 0)} />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 mr-2">تحويل (بنكك)</label>
                  <input type="number" className="w-full bg-slate-50 rounded-2xl p-4 font-black outline-none border-2 border-transparent focus:border-blue-500" value={bank} onChange={e => setBank(parseFloat(e.target.value) || 0)} />
                </div>
             </div>

             <div className={`p-5 rounded-[28px] border-2 transition-all ${isDebt ? 'bg-amber-50 border-amber-200' : 'bg-slate-50 border-transparent'}`}>
                <div className="flex justify-between items-center mb-4">
                   <div className="flex items-center gap-3">
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${isDebt ? 'bg-amber-500 text-white' : 'bg-slate-200 text-slate-400'}`}><UserPlus size={20}/></div>
                      <span className="font-black text-sm">تسجيل كدين (آجل)</span>
                   </div>
                   <input type="checkbox" className="w-6 h-6 accent-amber-500" checked={isDebt} onChange={e => setIsDebt(e.target.checked)} />
                </div>
                {isDebt && (
                  <select className="w-full bg-white rounded-xl p-3 font-bold text-sm outline-none border-2 border-amber-100" value={selectedCust || ''} onChange={e => setSelectedCust(parseInt(e.target.value) || null)}>
                    <option value="">اختر عميل من القائمة...</option>
                    {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                  </select>
                )}
             </div>

             <div className="pt-4 border-t border-slate-100 flex justify-between items-center pb-8">
                <div>
                   <div className="text-[10px] font-black text-slate-400">المتبقي / الدين</div>
                   <div className={`text-2xl font-black ${balance > 0 ? 'text-rose-500' : 'text-emerald-600'}`}>{Math.abs(balance).toFixed(2)}</div>
                </div>
                <button onClick={handleFinish} className="bg-emerald-600 text-white px-10 py-5 rounded-[28px] font-black text-lg shadow-xl active:scale-95 transition-all">تأكيد البيع</button>
             </div>
          </div>
       </div>
    </div>
  );
};

