import Dexie, { type Table } from 'dexie';
import { Medicine, Sale, Supplier, Customer } from './types';

// Fix: Use default import for Dexie to ensure all inherited methods like version() and transaction() are correctly recognized by TypeScript.
export class PharmacyDB extends Dexie {
  medicines!: Table<Medicine, number>;
  sales!: Table<Sale, number>;
  suppliers!: Table<Supplier, number>;
  customers!: Table<Customer, number>;

  constructor() {
    super('PharmacyDB');

    // The version() method is inherited from the Dexie base class and is used to define the database schema.
    this.version(4).stores({
      medicines: '++id, visualId, name, barcode, stock, expiryDate, category, salesCount, supplierId',
      sales: '++id, timestamp, customerId, paymentMethod',
      suppliers: '++id, name, phone',
      customers: '++id, name, phone, totalDebt'
    });
  }
}

export const db = new PharmacyDB();

