  constructor() {
    super('PharmacyDB');

    // التحديث للنسخة الرابعة لدعم حقول الموردين وتفاصيل الدفع المتقدمة
    this.version(4).stores({
      medicines: '++id, name, barcode, stock, expiryDate, category, salesCount, supplier',
      sales: '++id, timestamp, customerName, bankTrxId'
    });
  }
}

export const db = new PharmacyDB();

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { 
  Search, Plus, Package, BarChart3, ShoppingCart, X, Trash2, 
  CheckCircle2, History, TrendingUp, AlertCircle, Coins, 
  CreditCard, Wallet, UserMinus, Printer, ShoppingBag, 
  ArrowRight, Minus, Edit3, Truck, Receipt
} from 'lucide-react';
import { db } from './db';
import { Medicine, ViewType, Sale, CartItem } from './types';

const formatTime = (ts: number) => new Date(ts).toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' });

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('pos');
  const [accountingSubView, setAccountingSubView] = useState<'sales' | 'inventory'>('sales');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [salesHistory, setSalesHistory] = useState<Sale[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [cart, setCart] = useState<Map<number, CartItem>>(new Map());
  const [activeCategory, setActiveCategory] = useState<string>('الكل');

  const [isEditOpen, setIsEditOpen] = useState(false);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const [checkoutResult, setCheckoutResult] = useState<{status: 'success' | 'error', msg: string} | null>(null);

  // حقول الدفع المتقدمة
  const [discount, setDiscount] = useState(0);
  const [payCash, setPayCash] = useState(0);
  const [payBank, setPayBank] = useState(0);
  const [payDebt, setPayDebt] = useState(0);
  const [bankTrxId, setBankTrxId] = useState('');
  const [customerName, setCustomerName] = useState('');

  const loadData = useCallback(async () => {
    const [allMeds, allSales] = await Promise.all([
      db.medicines.toArray(),
      db.sales.orderBy('timestamp').reverse().toArray()
    ]);
    setMedicines(allMeds);
    setSalesHistory(allSales);
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const addToCart = (med: Medicine) => {
    if (med.id === undefined || med.stock <= 0) return;
    const newCart = new Map(cart);
    const qty = (newCart.get(med.id)?.quantity || 0) + 1;
    if (qty > med.stock) return;
    newCart.set(med.id, { medicine: med, quantity: qty });
    setCart(newCart);
  };

  const removeFromCart = (id: number) => {
    const newCart = new Map(cart);
    const item = newCart.get(id);
    if (item && item.quantity > 1) newCart.set(id, { ...item, quantity: item.quantity - 1 });
    else newCart.delete(id);
    setCart(newCart);
  };

  const cartTotal = useMemo(() => Array.from(cart.values()).reduce((sum, item) => sum + (item.medicine.price * item.quantity), 0), [cart]);
  const netAmount = useMemo(() => Math.max(0, cartTotal - discount), [cartTotal, discount]);
  const totalPaid = useMemo(() => (payCash + payBank + payDebt), [payCash, payBank, payDebt]);

  const handleFinalCheckout = async () => {
    if (Math.abs(totalPaid - netAmount) > 0.01) {
      alert("عذراً، يجب أن يتطابق مجموع (كاش + بنك + آجل) مع الصافي المطلوب.");
      return;
    }

    try {
      const items = Array.from(cart.values());
      const totalCost = items.reduce((sum, i) => sum + (i.medicine.costPrice * i.quantity), 0);

      await db.transaction('rw', ['medicines', 'sales'], async () => {
        for (const item of items) {
          const m = await db.medicines.get(item.medicine.id!);
          if (!m || m.stock < item.quantity) throw new Error(`نقص مخزون ${item.medicine.name}`);
          await db.medicines.update(m.id!, { 
            stock: m.stock - item.quantity,
            salesCount: (m.salesCount || 0) + item.quantity
          });
        }

        await db.sales.add({
          totalAmount: cartTotal,
          discount,
          netAmount,
          cashAmount: payCash,
          bankAmount: payBank,
          debtAmount: payDebt,
          bankTrxId: payBank > 0 ? bankTrxId : '',
          customerName: payDebt > 0 ? customerName : '',
          totalCost,
          timestamp: Date.now(),
          paymentMethod: 'split',
          itemsJson: JSON.stringify(items.map(i => ({ name: i.medicine.name, qty: i.quantity, price: i.medicine.price })))
        });
      });

      setCart(new Map());
      setIsCheckoutOpen(false);
      resetPaymentFields();
      setCheckoutResult({status: 'success', msg: 'تمت العملية بنجاح'});
      loadData();
    } catch (err: any) {
      setCheckoutResult({status: 'error', msg: err.message || 'فشلت العملية'});
    }
    setTimeout(() => setCheckoutResult(null), 4000);
  };

  const resetPaymentFields = () => {
    setDiscount(0); setPayCash(0); setPayBank(0); setPayDebt(0);
    setBankTrxId(''); setCustomerName('');
  };

  // إحصائيات رأس المال
  const inventoryStats = useMemo(() => {
    const totalValue = medicines.reduce((sum, m) => sum + (m.stock * m.costPrice), 0);
    const lowStockCount = medicines.filter(m => m.stock > 0 && m.stock < 10).length;
    return { totalValue, lowStockCount };
  }, [medicines]);

  const medicinesForPOS = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    return medicines.filter(m => 
      (m.name.toLowerCase().includes(q) || m.barcode.toLowerCase().includes(q)) &&
      (activeCategory === 'الكل' || m.category === activeCategory)
    ).sort((a, b) => (b.salesCount || 0) - (a.salesCount || 0));
  }, [medicines, searchQuery, activeCategory]);

  const categories = useMemo(() => ['الكل', ...Array.from(new Set(medicines.map(m => m.category || 'عام')))], [medicines]);

  return (
    <div className="flex flex-col h-screen bg-[#F8FAFC] text-slate-900 overflow-hidden">
      {/* Header */}
      <header className="bg-white px-6 pt-10 pb-6 shadow-sm z-20 shrink-0 border-b border-slate-100">
        <div className="flex justify-between items-center mb-6">
          <div>
            <h1 className="text-2xl font-black text-emerald-600 tracking-tight">صيدلية راحة</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">إدارة مالية ومخزنية متكاملة</p>
          </div>
          <div className="w-12 h-12 rounded-2xl bg-emerald-50 flex items-center justify-center text-emerald-600 shadow-sm">
            <ShoppingBag size={24} />
          </div>
        </div>
        <div className="relative group mb-4">
          <input 
            type="text" 
            placeholder="ابحث عن دواء..." 
            className="w-full bg-slate-50 text-slate-900 rounded-2xl py-4 pr-12 pl-4 text-lg font-bold border-2 border-transparent focus:border-emerald-500 focus:bg-white transition-all shadow-sm outline-none" 
            value={searchQuery} 
            onChange={(e) => setSearchQuery(e.target.value)} 
          />
          <Search className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-emerald-500 transition-colors" size={20} />
        </div>

        {view === 'pos' && (
          <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
            {categories.map(cat => (
              <button key={cat} onClick={() => setActiveCategory(cat)} className={`px-6 py-2 rounded-xl text-xs font-black whitespace-nowrap transition-all ${activeCategory === cat ? 'bg-emerald-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400'}`}>
                {cat}
              </button>
            ))}
          </div>
        )}
      </header>

      {/* Main View */}
      <main className="flex-grow overflow-y-auto p-4 pb-48 no-scrollbar">
        {view === 'pos' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
            {medicinesForPOS.map((med) => (
              <div key={med.id} onClick={() => addToCart(med)} onContextMenu={(e) => { e.preventDefault(); setEditingMedicine(med); setIsEditOpen(true); }}
                className={`group bg-white p-5 rounded-[28px] flex justify-between items-center transition-all shadow-sm border-2 ${cart.has(med.id!) ? 'border-emerald-500 bg-emerald-50/30' : 'border-transparent active:scale-95'}`}
              >
                <div>
                  <h3 className="font-bold text-lg text-slate-800 leading-tight flex items-center gap-2">
                    {med.name}
                    {cart.has(med.id!) && <span className="bg-emerald-600 text-white text-[10px] px-2 py-0.5 rounded-full font-black animate-in zoom-in">{cart.get(med.id!)?.quantity}</span>}
                  </h3>
                  <div className="flex items-center gap-3 mt-1">
                    <span className="text-[10px] font-bold text-slate-400 bg-slate-100 px-2 py-0.5 rounded-md">{med.category}</span>
                    <span className={`text-[10px] font-black ${med.stock < 10 ? 'text-rose-500' : 'text-emerald-600'}`}>{med.stock <= 0 ? 'نفذ' : `متاح: ${med.stock}`}</span>
                  </div>
                </div>
                <div className="text-left">
                  <div className="text-xl font-black text-emerald-700">{med.price.toFixed(2)}</div>
                  <div className="text-[9px] font-black text-slate-300 uppercase">جنيهاً</div>
                  {cart.has(med.id!) && (
                    <div className="flex items-center gap-2 mt-2 animate-in slide-in-from-left" onClick={e => e.stopPropagation()}>
                       <button onClick={() => removeFromCart(med.id!)} className="w-8 h-8 rounded-lg bg-rose-50 text-rose-500 flex items-center justify-center active:scale-90"><Minus size={14}/></button>
                       <button onClick={() => addToCart(med)} className="w-8 h-8 rounded-lg bg-emerald-600 text-white flex items-center justify-center active:scale-90"><Plus size={14}/></button>
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="space-y-6">
            <div className="flex bg-white/80 backdrop-blur-md p-1.5 rounded-2xl shadow-sm border border-slate-100 sticky top-0 z-10">
              <button onClick={() => setAccountingSubView('sales')} className={`flex-1 py-3 rounded-xl text-sm font-bold transition-all ${accountingSubView === 'sales' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}> المبيعات </button>
              <button onClick={() => setAccountingSubView('inventory')} className={`flex-1 py-3 rounded-xl text-sm font-bold transition-all ${accountingSubView === 'inventory' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}> المخزون والتقارير </button>
            </div>

            {accountingSubView === 'inventory' && (
              <div className="space-y-4">
                <div className="bg-emerald-600 p-8 rounded-[40px] text-white shadow-2xl shadow-emerald-200 relative overflow-hidden">
                   <TrendingUp className="absolute -bottom-10 -right-10 w-48 h-48 opacity-10" />
                   <div className="relative z-10">
                      <div className="text-4xl font-black tabular-nums">{inventoryStats.totalValue.toLocaleString()} <span className="text-sm font-normal opacity-70">ج.م</span></div>
                      <div className="text-[12px] font-bold opacity-80 mt-2 uppercase tracking-widest">إجمالي رأس مال المخزون (سعر الشراء)</div>
                      <div className="flex gap-4 mt-6">
                        <div className="bg-white/10 px-4 py-2 rounded-2xl border border-white/10 text-xs font-bold">عدد الأصناف: {medicines.length}</div>
                        <div className="bg-white/10 px-4 py-2 rounded-2xl border border-white/10 text-xs font-bold text-rose-100">النواقص: {inventoryStats.lowStockCount}</div>
                      </div>
                   </div>
                </div>

                <div className="grid grid-cols-1 gap-3">
                  {medicines.map(med => (
                    <div key={med.id} onClick={() => { setEditingMedicine(med); setIsEditOpen(true); }} className="bg-white p-5 rounded-[28px] flex justify-between items-center shadow-sm border border-slate-100 hover:border-emerald-200 transition-all">
                      <div className="flex items-center gap-4">
                          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${med.stock < 10 ? 'bg-rose-50 text-rose-500' : 'bg-emerald-50 text-emerald-500'}`}>
                              <Package size={22} />
                          </div>
                          <div>
                              <div className="font-bold text-slate-800">{med.name}</div>
                              <div className="text-[10px] text-slate-400 font-bold flex gap-2">
                                <span>المورد: {med.supplier || 'غير محدد'}</span>
                                <span>•</span>
                                <span>الفئة: {med.category}</span>
                              </div>
                          </div>
                      </div>
                      <div className="text-left">
                        <div className="text-xl font-black text-slate-700">{med.stock}</div>
                        <div className="text-[9px] font-bold text-slate-300 uppercase tracking-tighter">قطعة</div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {accountingSubView === 'sales' && (
              <div className="space-y-3">
                {salesHistory.map(sale => (
                  <div key={sale.id} className="bg-white p-5 rounded-[28px] border border-slate-100 flex flex-col gap-3">
                    <div className="flex justify-between items-center">
                      <div>
                        <div className="text-lg font-black text-slate-800">{sale.netAmount.toFixed(2)} ج.م</div>
                        <div className="text-[10px] text-slate-400 font-bold">{formatTime(sale.timestamp)} | {sale.customerName || 'زبون عام'}</div>
                      </div>
                      <div className="flex gap-2">
                         {sale.cashAmount > 0 && <div className="p-1.5 bg-emerald-50 text-emerald-600 rounded-lg"><Wallet size={14}/></div>}
                         {sale.bankAmount > 0 && <div className="p-1.5 bg-blue-50 text-blue-600 rounded-lg"><CreditCard size={14}/></div>}
                         {sale.debtAmount > 0 && <div className="p-1.5 bg-amber-50 text-amber-600 rounded-lg"><UserMinus size={14}/></div>}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </main>

      {/* Floating Checkout Bar */}
      {view === 'pos' && cart.size > 0 && (
        <div className="fixed bottom-28 left-0 right-0 px-6 z-40 animate-in slide-in-from-bottom duration-500">
          <div className="max-w-xl mx-auto bg-slate-900 text-white p-6 rounded-[35px] shadow-2xl border border-white/10 flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="w-14 h-14 rounded-2xl bg-white/10 flex items-center justify-center text-emerald-400 font-black text-xl">
                {Array.from(cart.values()).reduce((s, i) => s + i.quantity, 0)}
              </div>
              <div>
                <div className="text-2xl font-black tabular-nums">{cartTotal.toFixed(2)} <span className="text-[10px] font-normal opacity-50">ج.م</span></div>
                <div className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest">إجمالي السلة</div>
              </div>
            </div>
            <button onClick={() => { resetPaymentFields(); setPayCash(cartTotal); setIsCheckoutOpen(true); }} className="bg-emerald-500 hover:bg-emerald-400 text-white px-8 py-4 rounded-[22px] font-black text-lg shadow-xl active:scale-95 transition-all flex items-center gap-2">
              دفع وتثبيت <ArrowRight size={20} />
            </button>
          </div>
        </div>
      )}

      {/* Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-xl border-t border-slate-100 flex justify-around items-center px-4 pt-4 pb-10 z-30 shrink-0">
        <button onClick={() => setView('pos')} className={`flex flex-col items-center gap-1.5 transition-all ${view === 'pos' ? 'text-emerald-600' : 'text-slate-300'}`}> 
            <ShoppingCart size={26} strokeWidth={view === 'pos' ? 3 : 2} /> <span className="text-[10px] font-black uppercase">البيع</span> 
        </button>
        <button onClick={() => { setEditingMedicine(null); setIsEditOpen(true); }} className="relative -mt-16 bg-emerald-600 text-white w-18 h-18 rounded-3xl shadow-2xl flex items-center justify-center active:scale-90 transition-transform border-4 border-[#F8FAFC]">
            <Plus size={32} strokeWidth={3} />
        </button>
        <button onClick={() => setView('accounting')} className={`flex flex-col items-center gap-1.5 transition-all ${view === 'accounting' ? 'text-emerald-600' : 'text-slate-300'}`}> 
            <BarChart3 size={26} strokeWidth={view === 'accounting' ? 3 : 2} /> <span className="text-[10px] font-black uppercase">التقارير</span> 
        </button>
      </nav>

      {/* Checkout Modal */}
      {isCheckoutOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4 animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-lg rounded-t-[40px] sm:rounded-[45px] shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="p-8 pb-4 flex justify-between items-center shrink-0">
              <h2 className="text-2xl font-black text-slate-800">إتمام العملية</h2>
              <button onClick={() => setIsCheckoutOpen(false)} className="w-10 h-10 bg-slate-50 text-slate-400 rounded-2xl flex items-center justify-center"><X/></button>
            </div>

            <div className="p-8 pt-4 space-y-6 overflow-y-auto no-scrollbar pb-10">
               {/* فاتورة ملخصة */}
               <div className="bg-slate-50 p-6 rounded-[35px] border border-slate-100 flex justify-between items-center">
                  <div>
                    <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">الصافي المطلوب</div>
                    <div className="text-4xl font-black text-emerald-600 tabular-nums">{netAmount.toFixed(2)}</div>
                  </div>
                  <div className="text-left">
                    <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">قبل الخصم</div>
                    <div className="text-xl font-bold text-slate-300 line-through">{cartTotal.toFixed(2)}</div>
                  </div>
               </div>

               {/* حقل الخصم */}
               <div className="space-y-2">
                 <label className="text-[10px] font-black text-slate-400 mr-2 flex items-center gap-2"><Receipt size={14}/> مبلغ الخصم (ج.م)</label>
                 <input type="number" className="w-full bg-slate-50 border-2 border-transparent focus:border-emerald-500 rounded-2xl p-4 font-black text-lg outline-none transition-all" value={discount} onChange={e => setDiscount(parseFloat(e.target.value) || 0)} />
               </div>

               {/* توزيع المبالغ */}
               <div className="grid grid-cols-1 gap-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 mr-2 flex items-center gap-2"><Wallet size={14} className="text-emerald-500"/> كاش (نقدي)</label>
                    <input type="number" className="w-full bg-slate-50 border-2 border-emerald-100 focus:border-emerald-500 rounded-2xl p-4 font-black outline-none transition-all" value={payCash} onChange={e => setPayCash(parseFloat(e.target.value) || 0)} />
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 mr-2 flex items-center gap-2"><CreditCard size={14} className="text-blue-500"/> عبر البنك (بنكك/فيزا)</label>
                    <input type="number" className="w-full bg-slate-50 border-2 border-blue-100 focus:border-blue-500 rounded-2xl p-4 font-black outline-none transition-all" value={payBank} onChange={e => setPayBank(parseFloat(e.target.value) || 0)} />
                    {payBank > 0 && (
                      <input type="text" placeholder="رقم العملية البنكية..." className="w-full bg-blue-50/50 border-2 border-blue-200 rounded-xl p-3 text-sm font-bold outline-none animate-in zoom-in" value={bankTrxId} onChange={e => setBankTrxId(e.target.value)} />
                    )}
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 mr-2 flex items-center gap-2"><UserMinus size={14} className="text-amber-500"/> آجل (دين متبقي)</label>
                    <input type="number" className="w-full bg-slate-50 border-2 border-amber-100 focus:border-amber-500 rounded-2xl p-4 font-black outline-none transition-all" value={payDebt} onChange={e => setPayDebt(parseFloat(e.target.value) || 0)} />
                    {payDebt > 0 && (
                      <input type="text" placeholder="اسم الزبون الرباعي..." className="w-full bg-amber-50/50 border-2 border-amber-200 rounded-xl p-3 text-sm font-bold outline-none animate-in zoom-in" value={customerName} onChange={e => setCustomerName(e.target.value)} />
                    )}
                  </div>
               </div>

               {/* حالة التوزيع */}
               <div className={`p-4 rounded-2xl text-center font-black text-xs transition-all ${Math.abs(totalPaid - netAmount) < 0.01 ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-500'}`}>
                  {Math.abs(totalPaid - netAmount) < 0.01 ? 'التوزيع صحيح وجاهز للتأكيد' : `فرق التوزيع: ${(netAmount - totalPaid).toFixed(2)} ج.م`}
               </div>

               <button onClick={handleFinalCheckout} className="w-full bg-emerald-600 text-white py-5 rounded-[22px] font-black text-xl shadow-xl active:scale-95 transition-all">تأكيد البيع النهائي</button>
            </div>
          </div>
        </div>
      )}

      {/* Medicine Modal */}
      {isEditOpen && (
        <MedicineDialog 
          initialData={editingMedicine} 
          categories={categories.filter(c => c !== 'الكل')} 
          onSave={handleSaveMedicine} 
          onClose={() => setIsEditOpen(false)} 
          onDelete={async (id) => { if(confirm('حذف نهائي؟')) { await db.medicines.delete(id); setIsEditOpen(false); loadData(); } }} 
        />
      )}

      {/* Result Alert */}
      {checkoutResult && (
        <div className={`fixed top-8 left-6 right-6 z-[100] p-5 rounded-[28px] shadow-2xl flex items-center justify-between animate-in slide-in-from-top duration-500 ${checkoutResult.status === 'success' ? 'bg-emerald-600 text-white' : 'bg-rose-600 text-white'}`}>
          <div className="flex items-center gap-3">
            {checkoutResult.status === 'success' ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
            <span className="font-black">{checkoutResult.msg}</span>
          </div>
        </div>
      )}
    </div>
  );
};

const MedicineDialog: React.FC<{ initialData: Medicine | null; categories: string[]; onSave: (data: Medicine) => void; onClose: () => void; onDelete: (id: number) => void; }> = ({ initialData, categories, onSave, onClose, onDelete }) => {
  const [formData, setFormData] = useState<Medicine>( initialData || { name: '', barcode: '', price: 0, costPrice: 0, stock: 0, category: 'عام', expiryDate: new Date().toISOString().split('T')[0], supplier: '' } );
  const nameRef = useRef<HTMLInputElement>(null);
  useEffect(() => { if (nameRef.current) nameRef.current.focus(); }, []);

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4 animate-in fade-in">
      <div className="bg-white w-full max-w-lg rounded-t-[40px] sm:rounded-[45px] overflow-hidden shadow-2xl flex flex-col max-h-[90vh]">
        <div className="p-8 pb-4 flex justify-between items-center">
          <h2 className="text-2xl font-black text-slate-800">{initialData ? 'تعديل الصنف' : 'إضافة صنف جديد'}</h2>
          <button onClick={onClose} className="w-10 h-10 bg-slate-50 text-slate-400 rounded-2xl flex items-center justify-center"><X/></button>
        </div>
        <form onSubmit={(e) => { e.preventDefault(); onSave(formData); }} className="p-8 pt-4 space-y-5 overflow-y-auto no-scrollbar pb-10">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 mr-2 uppercase">اسم الدواء</label>
            <input ref={nameRef} type="text" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.name} required onChange={e => setFormData({...formData, name: e.target.value})}/>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 mr-2 uppercase">سعر البيع</label>
              <input type="number" step="0.01" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.price} required onChange={e => setFormData({...formData, price: parseFloat(e.target.value) || 0})}/>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 mr-2 uppercase">سعر الشراء</label>
              <input type="number" step="0.01" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.costPrice} required onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value) || 0})}/>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 mr-2 uppercase">الكمية</label>
              <input type="number" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.stock} required onChange={e => setFormData({...formData, stock: parseInt(e.target.value) || 0})}/>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 mr-2 uppercase">الفئة</label>
              <input type="text" list="cats-dialog" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})}/>
              <datalist id="cats-dialog">{categories.map(c => <option key={c} value={c}/>)}</datalist>
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 mr-2 uppercase flex items-center gap-2"><Truck size={14}/> اسم المورد</label>
            <input type="text" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.supplier} onChange={e => setFormData({...formData, supplier: e.target.value})}/>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 mr-2 uppercase">تاريخ الصلاحية</label>
            <input type="date" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.expiryDate} required onChange={e => setFormData({...formData, expiryDate: e.target.value})}/>
          </div>
          <div className="flex gap-4 pt-4">
            <button type="submit" className="flex-grow bg-emerald-600 text-white py-5 rounded-[22px] font-black text-xl shadow-xl active:scale-95">حفظ التغييرات</button>
            {initialData?.id && <button type="button" onClick={() => onDelete(initialData.id!)} className="bg-rose-50 text-rose-500 w-16 rounded-[22px] flex items-center justify-center active:scale-95"><Trash2 size={24} /></button>}
          </div>
        </form>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { 
  Search, Plus, Package, BarChart3, ShoppingCart, X, Trash2, 
  CheckCircle2, History, TrendingUp, AlertCircle, Coins, 
  CreditCard, Wallet, UserMinus, Printer, ShoppingBag, 
  ArrowRight, Minus, Edit3, Truck, Receipt
} from 'lucide-react';
import { db } from './db';
import { Medicine, ViewType, Sale, CartItem } from './types';

const formatTime = (ts: number) => new Date(ts).toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' });

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('pos');
  const [accountingSubView, setAccountingSubView] = useState<'sales' | 'inventory'>('sales');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [salesHistory, setSalesHistory] = useState<Sale[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [cart, setCart] = useState<Map<number, CartItem>>(new Map());
  const [activeCategory, setActiveCategory] = useState<string>('الكل');

  const [isEditOpen, setIsEditOpen] = useState(false);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const [checkoutResult, setCheckoutResult] = useState<{status: 'success' | 'error', msg: string} | null>(null);

  // حقول الدفع المتقدمة
  const [discount, setDiscount] = useState(0);
  const [payCash, setPayCash] = useState(0);
  const [payBank, setPayBank] = useState(0);
  const [payDebt, setPayDebt] = useState(0);
  const [bankTrxId, setBankTrxId] = useState('');
  const [customerName, setCustomerName] = useState('');

  const loadData = useCallback(async () => {
    const [allMeds, allSales] = await Promise.all([
      db.medicines.toArray(),
      db.sales.orderBy('timestamp').reverse().toArray()
    ]);
    setMedicines(allMeds);
    setSalesHistory(allSales);
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const addToCart = (med: Medicine) => {
    if (med.id === undefined || med.stock <= 0) return;
    const newCart = new Map(cart);
    const qty = (newCart.get(med.id)?.quantity || 0) + 1;
    if (qty > med.stock) return;
    newCart.set(med.id, { medicine: med, quantity: qty });
    setCart(newCart);
  };

  const removeFromCart = (id: number) => {
    const newCart = new Map(cart);
    const item = newCart.get(id);
    if (item && item.quantity > 1) newCart.set(id, { ...item, quantity: item.quantity - 1 });
    else newCart.delete(id);
    setCart(newCart);
  };

  const cartTotal = useMemo(() => Array.from(cart.values()).reduce((sum, item) => sum + (item.medicine.price * item.quantity), 0), [cart]);
  const netAmount = useMemo(() => Math.max(0, cartTotal - discount), [cartTotal, discount]);
  const totalPaid = useMemo(() => (payCash + payBank + payDebt), [payCash, payBank, payDebt]);

  const handleFinalCheckout = async () => {
    if (Math.abs(totalPaid - netAmount) > 0.01) {
      alert("عذراً، يجب أن يتطابق مجموع (كاش + بنك + آجل) مع الصافي المطلوب.");
      return;
    }

    try {
      const items = Array.from(cart.values());
      const totalCost = items.reduce((sum, i) => sum + (i.medicine.costPrice * i.quantity), 0);

      await db.transaction('rw', ['medicines', 'sales'], async () => {
        for (const item of items) {
          const m = await db.medicines.get(item.medicine.id!);
          if (!m || m.stock < item.quantity) throw new Error(`نقص مخزون ${item.medicine.name}`);
          await db.medicines.update(m.id!, { 
            stock: m.stock - item.quantity,
            salesCount: (m.salesCount || 0) + item.quantity
          });
        }

        await db.sales.add({
          totalAmount: cartTotal,
          discount,
          netAmount,
          cashAmount: payCash,
          bankAmount: payBank,
          debtAmount: payDebt,
          bankTrxId: payBank > 0 ? bankTrxId : '',
          customerName: payDebt > 0 ? customerName : '',
          totalCost,
          timestamp: Date.now(),
          paymentMethod: 'split',
          itemsJson: JSON.stringify(items.map(i => ({ name: i.medicine.name, qty: i.quantity, price: i.medicine.price })))
        });
      });

      setCart(new Map());
      setIsCheckoutOpen(false);
      resetPaymentFields();
      setCheckoutResult({status: 'success', msg: 'تمت العملية بنجاح'});
      loadData();
    } catch (err: any) {
      setCheckoutResult({status: 'error', msg: err.message || 'فشلت العملية'});
    }
    setTimeout(() => setCheckoutResult(null), 4000);
  };

  const resetPaymentFields = () => {
    setDiscount(0); setPayCash(0); setPayBank(0); setPayDebt(0);
    setBankTrxId(''); setCustomerName('');
  };

  // Fix: handleSaveMedicine function implementation
  const handleSaveMedicine = async (data: Medicine) => {
    try {
      if (data.id) {
        await db.medicines.update(data.id, data);
      } else {
        await db.medicines.add(data);
      }
      setIsEditOpen(false);
      loadData();
    } catch (err: any) {
      console.error("Save error:", err);
      alert("حدث خطأ أثناء حفظ البيانات");
    }
  };

  // إحصائيات رأس المال
  const inventoryStats = useMemo(() => {
    const totalValue = medicines.reduce((sum, m) => sum + (m.stock * m.costPrice), 0);
    const lowStockCount = medicines.filter(m => m.stock > 0 && m.stock < 10).length;
    return { totalValue, lowStockCount };
  }, [medicines]);

  const medicinesForPOS = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    return medicines.filter(m => 
      (m.name.toLowerCase().includes(q) || m.barcode.toLowerCase().includes(q)) &&
      (activeCategory === 'الكل' || m.category === activeCategory)
    ).sort((a, b) => (b.salesCount || 0) - (a.salesCount || 0));
  }, [medicines, searchQuery, activeCategory]);

  const categories = useMemo(() => ['الكل', ...Array.from(new Set(medicines.map(m => m.category || 'عام')))], [medicines]);

  return (
    <div className="flex flex-col h-screen bg-[#F8FAFC] text-slate-900 overflow-hidden">
      {/* Header */}
      <header className="bg-white px-6 pt-10 pb-6 shadow-sm z-20 shrink-0 border-b border-slate-100">
        <div className="flex justify-between items-center mb-6">
          <div>
            <h1 className="text-2xl font-black text-emerald-600 tracking-tight">صيدلية راحة</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">إدارة مالية ومخزنية متكاملة</p>
          </div>
          <div className="w-12 h-12 rounded-2xl bg-emerald-50 flex items-center justify-center text-emerald-600 shadow-sm">
            <ShoppingBag size={24} />
          </div>
        </div>
        <div className="relative group mb-4">
          <input 
            type="text" 
            placeholder="ابحث عن دواء..." 
            className="w-full bg-slate-50 text-slate-900 rounded-2xl py-4 pr-12 pl-4 text-lg font-bold border-2 border-transparent focus:border-emerald-500 focus:bg-white transition-all shadow-sm outline-none" 
            value={searchQuery} 
            onChange={(e) => setSearchQuery(e.target.value)} 
          />
          <Search className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-emerald-500 transition-colors" size={20} />
        </div>

        {view === 'pos' && (
          <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
            {categories.map(cat => (
              <button key={cat} onClick={() => setActiveCategory(cat)} className={`px-6 py-2 rounded-xl text-xs font-black whitespace-nowrap transition-all ${activeCategory === cat ? 'bg-emerald-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400'}`}>
                {cat}
              </button>
            ))}
          </div>
        )}
      </header>

      {/* Main View */}
      <main className="flex-grow overflow-y-auto p-4 pb-48 no-scrollbar">
        {view === 'pos' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
            {medicinesForPOS.map((med) => (
              <div key={med.id} onClick={() => addToCart(med)} onContextMenu={(e) => { e.preventDefault(); setEditingMedicine(med); setIsEditOpen(true); }}
                className={`group bg-white p-5 rounded-[28px] flex justify-between items-center transition-all shadow-sm border-2 ${cart.has(med.id!) ? 'border-emerald-500 bg-emerald-50/30' : 'border-transparent active:scale-95'}`}
              >
                <div>
                  <h3 className="font-bold text-lg text-slate-800 leading-tight flex items-center gap-2">
                    {med.name}
                    {cart.has(med.id!) && <span className="bg-emerald-600 text-white text-[10px] px-2 py-0.5 rounded-full font-black animate-in zoom-in">{cart.get(med.id!)?.quantity}</span>}
                  </h3>
                  <div className="flex items-center gap-3 mt-1">
                    <span className="text-[10px] font-bold text-slate-400 bg-slate-100 px-2 py-0.5 rounded-md">{med.category}</span>
                    <span className={`text-[10px] font-black ${med.stock < 10 ? 'text-rose-500' : 'text-emerald-600'}`}>{med.stock <= 0 ? 'نفذ' : `متاح: ${med.stock}`}</span>
                  </div>
                </div>
                <div className="text-left">
                  <div className="text-xl font-black text-emerald-700">{med.price.toFixed(2)}</div>
                  <div className="text-[9px] font-black text-slate-300 uppercase">جنيهاً</div>
                  {cart.has(med.id!) && (
                    <div className="flex items-center gap-2 mt-2 animate-in slide-in-from-left" onClick={e => e.stopPropagation()}>
                       <button onClick={() => removeFromCart(med.id!)} className="w-8 h-8 rounded-lg bg-rose-50 text-rose-500 flex items-center justify-center active:scale-90"><Minus size={14}/></button>
                       <button onClick={() => addToCart(med)} className="w-8 h-8 rounded-lg bg-emerald-600 text-white flex items-center justify-center active:scale-90"><Plus size={14}/></button>
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="space-y-6">
            <div className="flex bg-white/80 backdrop-blur-md p-1.5 rounded-2xl shadow-sm border border-slate-100 sticky top-0 z-10">
              <button onClick={() => setAccountingSubView('sales')} className={`flex-1 py-3 rounded-xl text-sm font-bold transition-all ${accountingSubView === 'sales' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}> المبيعات </button>
              <button onClick={() => setAccountingSubView('inventory')} className={`flex-1 py-3 rounded-xl text-sm font-bold transition-all ${accountingSubView === 'inventory' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}> المخزون والتقارير </button>
            </div>

            {accountingSubView === 'inventory' && (
              <div className="space-y-4">
                <div className="bg-emerald-600 p-8 rounded-[40px] text-white shadow-2xl shadow-emerald-200 relative overflow-hidden">
                   <TrendingUp className="absolute -bottom-10 -right-10 w-48 h-48 opacity-10" />
                   <div className="relative z-10">
                      <div className="text-4xl font-black tabular-nums">{inventoryStats.totalValue.toLocaleString()} <span className="text-sm font-normal opacity-70">ج.م</span></div>
                      <div className="text-[12px] font-bold opacity-80 mt-2 uppercase tracking-widest">إجمالي رأس مال المخزون (سعر الشراء)</div>
                      <div className="flex gap-4 mt-6">
                        <div className="bg-white/10 px-4 py-2 rounded-2xl border border-white/10 text-xs font-bold">عدد الأصناف: {medicines.length}</div>
                        <div className="bg-white/10 px-4 py-2 rounded-2xl border border-white/10 text-xs font-bold text-rose-100">النواقص: {inventoryStats.lowStockCount}</div>
                      </div>
                   </div>
                </div>

                <div className="grid grid-cols-1 gap-3">
                  {medicines.map(med => (
                    <div key={med.id} onClick={() => { setEditingMedicine(med); setIsEditOpen(true); }} className="bg-white p-5 rounded-[28px] flex justify-between items-center shadow-sm border border-slate-100 hover:border-emerald-200 transition-all">
                      <div className="flex items-center gap-4">
                          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${med.stock < 10 ? 'bg-rose-50 text-rose-500' : 'bg-emerald-50 text-emerald-500'}`}>
                              <Package size={22} />
                          </div>
                          <div>
                              <div className="font-bold text-slate-800">{med.name}</div>
                              <div className="text-[10px] text-slate-400 font-bold flex gap-2">
                                <span>المورد: {med.supplier || 'غير محدد'}</span>
                                <span>•</span>
                                <span>الفئة: {med.category}</span>
                              </div>
                          </div>
                      </div>
                      <div className="text-left">
                        <div className="text-xl font-black text-slate-700">{med.stock}</div>
                        <div className="text-[9px] font-bold text-slate-300 uppercase tracking-tighter">قطعة</div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {accountingSubView === 'sales' && (
              <div className="space-y-3">
                {salesHistory.map(sale => (
                  <div key={sale.id} className="bg-white p-5 rounded-[28px] border border-slate-100 flex flex-col gap-3">
                    <div className="flex justify-between items-center">
                      <div>
                        <div className="text-lg font-black text-slate-800">{sale.netAmount.toFixed(2)} ج.م</div>
                        <div className="text-[10px] text-slate-400 font-bold">{formatTime(sale.timestamp)} | {sale.customerName || 'زبون عام'}</div>
                      </div>
                      <div className="flex gap-2">
                         {sale.cashAmount > 0 && <div className="p-1.5 bg-emerald-50 text-emerald-600 rounded-lg"><Wallet size={14}/></div>}
                         {sale.bankAmount > 0 && <div className="p-1.5 bg-blue-50 text-blue-600 rounded-lg"><CreditCard size={14}/></div>}
                         {sale.debtAmount > 0 && <div className="p-1.5 bg-amber-50 text-amber-600 rounded-lg"><UserMinus size={14}/></div>}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </main>

      {/* Floating Checkout Bar */}
      {view === 'pos' && cart.size > 0 && (
        <div className="fixed bottom-28 left-0 right-0 px-6 z-40 animate-in slide-in-from-bottom duration-500">
          <div className="max-w-xl mx-auto bg-slate-900 text-white p-6 rounded-[35px] shadow-2xl border border-white/10 flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="w-14 h-14 rounded-2xl bg-white/10 flex items-center justify-center text-emerald-400 font-black text-xl">
                {Array.from(cart.values()).reduce((s, i) => s + i.quantity, 0)}
              </div>
              <div>
                <div className="text-2xl font-black tabular-nums">{cartTotal.toFixed(2)} <span className="text-[10px] font-normal opacity-50">ج.م</span></div>
                <div className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest">إجمالي السلة</div>
              </div>
            </div>
            <button onClick={() => { resetPaymentFields(); setPayCash(cartTotal); setIsCheckoutOpen(true); }} className="bg-emerald-500 hover:bg-emerald-400 text-white px-8 py-4 rounded-[22px] font-black text-lg shadow-xl active:scale-95 transition-all flex items-center gap-2">
              دفع وتثبيت <ArrowRight size={20} />
            </button>
          </div>
        </div>
      )}

      {/* Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-xl border-t border-slate-100 flex justify-around items-center px-4 pt-4 pb-10 z-30 shrink-0">
        <button onClick={() => setView('pos')} className={`flex flex-col items-center gap-1.5 transition-all ${view === 'pos' ? 'text-emerald-600' : 'text-slate-300'}`}> 
            <ShoppingCart size={26} strokeWidth={view === 'pos' ? 3 : 2} /> <span className="text-[10px] font-black uppercase">البيع</span> 
        </button>
        <button onClick={() => { setEditingMedicine(null); setIsEditOpen(true); }} className="relative -mt-16 bg-emerald-600 text-white w-18 h-18 rounded-3xl shadow-2xl flex items-center justify-center active:scale-90 transition-transform border-4 border-[#F8FAFC]">
            <Plus size={32} strokeWidth={3} />
        </button>
        <button onClick={() => setView('accounting')} className={`flex flex-col items-center gap-1.5 transition-all ${view === 'accounting' ? 'text-emerald-600' : 'text-slate-300'}`}> 
            <BarChart3 size={26} strokeWidth={view === 'accounting' ? 3 : 2} /> <span className="text-[10px] font-black uppercase">التقارير</span> 
        </button>
      </nav>

      {/* Checkout Modal */}
      {isCheckoutOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4 animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-lg rounded-t-[40px] sm:rounded-[45px] shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="p-8 pb-4 flex justify-between items-center shrink-0">
              <h2 className="text-2xl font-black text-slate-800">إتمام العملية</h2>
              <button onClick={() => setIsCheckoutOpen(false)} className="w-10 h-10 bg-slate-50 text-slate-400 rounded-2xl flex items-center justify-center"><X/></button>
            </div>

            <div className="p-8 pt-4 space-y-6 overflow-y-auto no-scrollbar pb-10">
               {/* فاتورة ملخصة */}
               <div className="bg-slate-50 p-6 rounded-[35px] border border-slate-100 flex justify-between items-center">
                  <div>
                    <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">الصافي المطلوب</div>
                    <div className="text-4xl font-black text-emerald-600 tabular-nums">{netAmount.toFixed(2)}</div>
                  </div>
                  <div className="text-left">
                    <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">قبل الخصم</div>
                    <div className="text-xl font-bold text-slate-300 line-through">{cartTotal.toFixed(2)}</div>
                  </div>
               </div>

               {/* حقل الخصم */}
               <div className="space-y-2">
                 <label className="text-[10px] font-black text-slate-400 mr-2 flex items-center gap-2"><Receipt size={14}/> مبلغ الخصم (ج.م)</label>
                 <input type="number" className="w-full bg-slate-50 border-2 border-transparent focus:border-emerald-500 rounded-2xl p-4 font-black text-lg outline-none transition-all" value={discount} onChange={e => setDiscount(parseFloat(e.target.value) || 0)} />
               </div>

               {/* توزيع المبالغ */}
               <div className="grid grid-cols-1 gap-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 mr-2 flex items-center gap-2"><Wallet size={14} className="text-emerald-500"/> كاش (نقدي)</label>
                    <input type="number" className="w-full bg-slate-50 border-2 border-emerald-100 focus:border-emerald-500 rounded-2xl p-4 font-black outline-none transition-all" value={payCash} onChange={e => setPayCash(parseFloat(e.target.value) || 0)} />
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 mr-2 flex items-center gap-2"><CreditCard size={14} className="text-blue-500"/> عبر البنك (بنكك/فيزا)</label>
                    <input type="number" className="w-full bg-slate-50 border-2 border-blue-100 focus:border-blue-500 rounded-2xl p-4 font-black outline-none transition-all" value={payBank} onChange={e => setPayBank(parseFloat(e.target.value) || 0)} />
                    {payBank > 0 && (
                      <input type="text" placeholder="رقم العملية البنكية..." className="w-full bg-blue-50/50 border-2 border-blue-200 rounded-xl p-3 text-sm font-bold outline-none animate-in zoom-in" value={bankTrxId} onChange={e => setBankTrxId(e.target.value)} />
                    )}
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 mr-2 flex items-center gap-2"><UserMinus size={14} className="text-amber-500"/> آجل (دين متبقي)</label>
                    <input type="number" className="w-full bg-slate-50 border-2 border-amber-100 focus:border-amber-500 rounded-2xl p-4 font-black outline-none transition-all" value={payDebt} onChange={e => setPayDebt(parseFloat(e.target.value) || 0)} />
                    {payDebt > 0 && (
                      <input type="text" placeholder="اسم الزبون الرباعي..." className="w-full bg-amber-50/50 border-2 border-amber-200 rounded-xl p-3 text-sm font-bold outline-none animate-in zoom-in" value={customerName} onChange={e => setCustomerName(e.target.value)} />
                    )}
                  </div>
               </div>

               {/* حالة التوزيع */}
               <div className={`p-4 rounded-2xl text-center font-black text-xs transition-all ${Math.abs(totalPaid - netAmount) < 0.01 ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-500'}`}>
                  {Math.abs(totalPaid - netAmount) < 0.01 ? 'التوزيع صحيح وجاهز للتأكيد' : `فرق التوزيع: ${(netAmount - totalPaid).toFixed(2)} ج.م`}
               </div>

               <button onClick={handleFinalCheckout} className="w-full bg-emerald-600 text-white py-5 rounded-[22px] font-black text-xl shadow-xl active:scale-95 transition-all">تأكيد البيع النهائي</button>
            </div>
          </div>
        </div>
      )}

      {/* Medicine Modal */}
      {isEditOpen && (
        <MedicineDialog 
          initialData={editingMedicine} 
          categories={categories.filter(c => c !== 'الكل')} 
          onSave={handleSaveMedicine} 
          onClose={() => setIsEditOpen(false)} 
          onDelete={async (id) => { if(confirm('حذف نهائي؟')) { await db.medicines.delete(id); setIsEditOpen(false); loadData(); } }} 
        />
      )}

      {/* Result Alert */}
      {checkoutResult && (
        <div className={`fixed top-8 left-6 right-6 z-[100] p-5 rounded-[28px] shadow-2xl flex items-center justify-between animate-in slide-in-from-top duration-500 ${checkoutResult.status === 'success' ? 'bg-emerald-600 text-white' : 'bg-rose-600 text-white'}`}>
          <div className="flex items-center gap-3">
            {checkoutResult.status === 'success' ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
            <span className="font-black">{checkoutResult.msg}</span>
          </div>
        </div>
      )}
    </div>
  );
};

const MedicineDialog: React.FC<{ initialData: Medicine | null; categories: string[]; onSave: (data: Medicine) => void; onClose: () => void; onDelete: (id: number) => void; }> = ({ initialData, categories, onSave, onClose, onDelete }) => {
  const [formData, setFormData] = useState<Medicine>( initialData || { name: '', barcode: '', price: 0, costPrice: 0, stock: 0, category: 'عام', expiryDate: new Date().toISOString().split('T')[0], supplier: '' } );
  const nameRef = useRef<HTMLInputElement>(null);
  useEffect(() => { if (nameRef.current) nameRef.current.focus(); }, []);

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4 animate-in fade-in">
      <div className="bg-white w-full max-w-lg rounded-t-[40px] sm:rounded-[45px] overflow-hidden shadow-2xl flex flex-col max-h-[90vh]">
        <div className="p-8 pb-4 flex justify-between items-center">
          <h2 className="text-2xl font-black text-slate-800">{initialData ? 'تعديل الصنف' : 'إضافة صنف جديد'}</h2>
          <button onClick={onClose} className="w-10 h-10 bg-slate-50 text-slate-400 rounded-2xl flex items-center justify-center"><X/></button>
        </div>
        <form onSubmit={(e) => { e.preventDefault(); onSave(formData); }} className="p-8 pt-4 space-y-5 overflow-y-auto no-scrollbar pb-10">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 mr-2 uppercase">اسم الدواء</label>
            <input ref={nameRef} type="text" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.name} required onChange={e => setFormData({...formData, name: e.target.value})}/>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 mr-2 uppercase">سعر البيع</label>
              <input type="number" step="0.01" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.price} required onChange={e => setFormData({...formData, price: parseFloat(e.target.value) || 0})}/>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 mr-2 uppercase">سعر الشراء</label>
              <input type="number" step="0.01" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.costPrice} required onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value) || 0})}/>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 mr-2 uppercase">الكمية</label>
              <input type="number" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.stock} required onChange={e => setFormData({...formData, stock: parseInt(e.target.value) || 0})}/>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 mr-2 uppercase">الفئة</label>
              <input type="text" list="cats-dialog" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})}/>
              <datalist id="cats-dialog">{categories.map(c => <option key={c} value={c}/>)}</datalist>
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 mr-2 uppercase flex items-center gap-2"><Truck size={14}/> اسم المورد</label>
            <input type="text" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.supplier} onChange={e => setFormData({...formData, supplier: e.target.value})}/>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 mr-2 uppercase">تاريخ الصلاحية</label>
            <input type="date" className="w-full bg-slate-50 border-2 border-transparent rounded-2xl p-4 font-bold focus:border-emerald-500 outline-none" value={formData.expiryDate} required onChange={e => setFormData({...formData, expiryDate: e.target.value})}/>
          </div>
          <div className="flex gap-4 pt-4">
            <button type="submit" className="flex-grow bg-emerald-600 text-white py-5 rounded-[22px] font-black text-xl shadow-xl active:scale-95">حفظ التغييرات</button>
            {initialData?.id && <button type="button" onClick={() => onDelete(initialData.id!)} className="bg-rose-50 text-rose-500 w-16 rounded-[22px] flex items-center justify-center active:scale-95"><Trash2 size={24} /></button>}
          </div>
        </form>
      </div>
    </div>
  );
};

export default App;

export interface Medicine {
  id?: number;
  name: string;
  barcode: string;
  price: number;
  costPrice: number;
  stock: number;
  category: string;
  expiryDate: string;
  supplier?: string;
  usageCount: number; // لتتبع الأكثر استخداماً
  lastSold?: number;  // لتتبع الأصناف الراكدة
}

export interface Expense {
  id?: number;
  amount: number;
  type: string;
  description: string;
  timestamp: number;
}

export interface Sale {
  id?: number;
  totalAmount: number;
  discount: number;
  netAmount: number;
  cashAmount: number;
  bankAmount: number;
  debtAmount: number;
  bankTrxId?: string;
  customerName?: string;
  totalCost: number;
  profit: number; // الربح الصافي للعملية
  timestamp: number;
  itemsJson: string; 
  isReturned?: boolean; // علامة المرتجع
}

export interface CartItem {
  medicine: Medicine;
  quantity: number;
}

export type ViewType = 'pos' | 'accounting' | 'inventory' | 'expenses';

import Dexie, { type Table } from 'dexie';
import { Medicine, Sale, Expense } from './types';

export class RahaDB extends Dexie {
  medicines!: Table<Medicine, number>;
  sales!: Table<Sale, number>;
  expenses!: Table<Expense, number>;

  constructor() {
    super('RahaDB');
    this.version(5).stores({
      medicines: '++id, name, barcode, category, usageCount, lastSold, supplier',
      sales: '++id, timestamp, customerName, isReturned',
      expenses: '++id, timestamp, type'
    });
  }
}

export const db = new RahaDB();

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { 
  Search, Plus, Package, BarChart3, ShoppingCart, X, Trash2, 
  CheckCircle2, History, TrendingUp, AlertCircle, Coins, 
  CreditCard, Wallet, UserMinus, Printer, ShoppingBag, 
  ArrowRight, Minus, Edit3, Truck, Receipt, Calendar, 
  RotateCcw, Save, Download, Filter, Trash, ArrowDownRight, Layers
} from 'lucide-react';
import { db } from './db';
import { Medicine, ViewType, Sale, CartItem, Expense } from './types';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('pos');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [salesHistory, setSalesHistory] = useState<Sale[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState('الكل');

  // Inventory Filters
  const [invFilter, setInvFilter] = useState<'all' | 'low' | 'expired' | 'stagnant'>('all');

  // Checkout State
  const [cart, setCart] = useState<Map<number, CartItem>>(new Map());
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [isEditOpen, setIsEditOpen] = useState(false);
  const [editingMed, setEditingMed] = useState<Medicine | null>(null);

  // Split Payment State
  const [payData, setPayData] = useState({ discount: 0, cash: 0, bank: 0, debt: 0, trx: '', cust: '' });

  const loadData = useCallback(async () => {
    const [m, s, e] = await Promise.all([
      db.medicines.toArray(),
      db.sales.orderBy('timestamp').reverse().toArray(),
      db.expenses.orderBy('timestamp').reverse().toArray()
    ]);
    setMedicines(m);
    setSalesHistory(s);
    setExpenses(e);
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  // Logic: Dynamic Sorting by Usage
  const categories = useMemo(() => {
    const cats = Array.from(new Set(medicines.map(m => m.category || 'عام')));
    const usageMap = medicines.reduce((acc, m) => {
      acc[m.category] = (acc[m.category] || 0) + (m.usageCount || 0);
      return acc;
    }, {} as Record<string, number>);
    return ['الكل', ...cats.sort((a, b) => (usageMap[b] || 0) - (usageMap[a] || 0))];
  }, [medicines]);

  const posItems = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    return medicines
      .filter(m => (m.name.toLowerCase().includes(q) || m.barcode.includes(q)) && (activeCategory === 'الكل' || m.category === activeCategory))
      .sort((a, b) => (b.usageCount || 0) - (a.usageCount || 0));
  }, [medicines, searchQuery, activeCategory]);

  const filteredInventory = useMemo(() => {
    const now = Date.now();
    return medicines.filter(m => {
      if (invFilter === 'low') return m.stock <= 5;
      if (invFilter === 'expired') return new Date(m.expiryDate).getTime() < now;
      if (invFilter === 'stagnant') return !m.lastSold || (now - m.lastSold > 60 * 24 * 60 * 60 * 1000);
      return true;
    });
  }, [medicines, invFilter]);

  const inventoryValue = useMemo(() => {
    return filteredInventory.reduce((acc, m) => {
      acc.cost += m.stock * m.costPrice;
      acc.sell += m.stock * m.price;
      return acc;
    }, { cost: 0, sell: 0 });
  }, [filteredInventory]);

  const stats = useMemo(() => {
    const today = new Date().setHours(0,0,0,0);
    const todaySales = salesHistory.filter(s => s.timestamp >= today && !s.isReturned);
    const totalSales = todaySales.reduce((sum, s) => sum + s.netAmount, 0);
    const totalCost = todaySales.reduce((sum, s) => sum + s.totalCost, 0);
    const todayExpenses = expenses.filter(e => e.timestamp >= today).reduce((sum, e) => sum + e.amount, 0);
    return { sales: totalSales, profit: totalSales - totalCost, expenses: todayExpenses, net: totalSales - totalCost - todayExpenses };
  }, [salesHistory, expenses]);

  // Actions
  const addToCart = (m: Medicine) => {
    if (m.stock <= 0) return;
    const newCart = new Map(cart);
    const item = newCart.get(m.id!) || { medicine: m, quantity: 0 };
    if (item.quantity < m.stock) {
      newCart.set(m.id!, { ...item, quantity: item.quantity + 1 });
      setCart(newCart);
    }
  };

  const handleSale = async () => {
    const cartTotal = Array.from(cart.values()).reduce((s, i) => s + (i.medicine.price * i.quantity), 0);
    const net = cartTotal - payData.discount;
    if (Math.abs((payData.cash + payData.bank + payData.debt) - net) > 0.1) {
      alert("خطأ في توزيع المبلغ"); return;
    }

    await db.transaction('rw', [db.medicines, db.sales], async () => {
      const items = Array.from(cart.values());
      const totalCost = items.reduce((s, i) => s + (i.medicine.costPrice * i.quantity), 0);

      for (const item of items) {
        await db.medicines.update(item.medicine.id!, {
          stock: item.medicine.stock - item.quantity,
          usageCount: (item.medicine.usageCount || 0) + item.quantity,
          lastSold: Date.now()
        });
      }

      await db.sales.add({
        totalAmount: cartTotal,
        discount: payData.discount,
        netAmount: net,
        cashAmount: payData.cash,
        bankAmount: payData.bank,
        debtAmount: payData.debt,
        bankTrxId: payData.trx,
        customerName: payData.cust,
        totalCost,
        profit: net - totalCost,
        timestamp: Date.now(),
        itemsJson: JSON.stringify(items),
        paymentMethod: 'split'
      });
    });

    setCart(new Map());
    setIsCheckoutOpen(false);
    setPayData({ discount: 0, cash: 0, bank: 0, debt: 0, trx: '', cust: '' });
    loadData();
  };

  const handleReturn = async (sale: Sale) => {
    if (!confirm("هل تريد إرجاع هذه العملية؟ سيتم إعادة المنتجات للمخزن.")) return;
    await db.transaction('rw', [db.medicines, db.sales], async () => {
      const items = JSON.parse(sale.itemsJson);
      for (const item of items) {
        const m = await db.medicines.get(item.medicine.id);
        if (m) await db.medicines.update(m.id!, { stock: m.stock + item.quantity });
      }
      await db.sales.update(sale.id!, { isReturned: true });
    });
    loadData();
  };

  const backupData = async () => {
    const data = { medicines, sales: salesHistory, expenses };
    const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = `raha_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
  };

  const resetAll = async () => {
    if (!confirm("تحذير: سيتم مسح كافة سجلات المبيعات والمصاريف وتصفير النظام. هل قمت بعمل نسخة احتياطية؟")) return;
    await db.sales.clear();
    await db.expenses.clear();
    // تصفير عدادات الاستخدام في المخزن
    const allMeds = await db.medicines.toArray();
    for (const m of allMeds) await db.medicines.update(m.id!, { usageCount: 0, lastSold: undefined });
    loadData();
    alert("تم تصفير النظام بنجاح.");
  };

  const inlineUpdate = async (id: number, field: string, val: string) => {
    const n = parseFloat(val);
    if (!isNaN(n)) {
      await db.medicines.update(id, { [field]: n });
      loadData();
    }
  };

  return (
    <div className="flex flex-col h-screen bg-[#F8FAFC] text-slate-900 overflow-hidden font-medium">
      {/* Top Header */}
      <header className="bg-white px-6 pt-10 pb-4 shadow-sm z-30 border-b border-slate-100 shrink-0">
        <div className="flex justify-between items-center mb-6">
          <div>
            <h1 className="text-2xl font-black text-emerald-600 flex items-center gap-2">
              <Layers className="text-emerald-500" /> راحة <span className="text-slate-300 font-light">|</span> <span className="text-slate-400 text-sm font-bold">PRO</span>
            </h1>
          </div>
          <div className="flex gap-2">
            <button onClick={backupData} className="p-2.5 bg-slate-50 text-slate-400 rounded-xl hover:bg-emerald-50 hover:text-emerald-600 transition-all"><Download size={20} /></button>
            <button onClick={resetAll} className="p-2.5 bg-slate-50 text-rose-400 rounded-xl hover:bg-rose-100 transition-all"><RotateCcw size={20} /></button>
          </div>
        </div>

        <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
          {['pos', 'inventory', 'accounting', 'expenses'].map((v) => (
            <button key={v} onClick={() => setView(v as ViewType)} className={`px-6 py-2.5 rounded-2xl text-xs font-black whitespace-nowrap transition-all ${view === v ? 'bg-emerald-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400'}`}>
              {v === 'pos' ? 'نقطة البيع' : v === 'inventory' ? 'المخزن' : v === 'accounting' ? 'التقارير' : 'المنصرفات'}
            </button>
          ))}
        </div>
      </header>

      {/* Main Container */}
      <main className="flex-grow overflow-y-auto p-4 pb-40 no-scrollbar">
        {view === 'pos' && (
          <div className="animate-in fade-in duration-300">
            <div className="relative mb-4">
              <input type="text" placeholder="بحث سريع..." className="w-full bg-white rounded-2xl py-4 pr-12 pl-4 text-lg font-bold shadow-sm border-2 border-transparent focus:border-emerald-500 outline-none transition-all" value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
              <Search className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300" />
            </div>

            <div className="flex gap-2 overflow-x-auto no-scrollbar mb-4">
              {categories.map(c => (
                <button key={c} onClick={() => setActiveCategory(c)} className={`px-5 py-2 rounded-xl text-[10px] font-black transition-all ${activeCategory === c ? 'bg-emerald-100 text-emerald-700' : 'bg-white text-slate-400 shadow-sm'}`}>{c}</button>
              ))}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
              {posItems.map(m => (
                <div key={m.id} onClick={() => addToCart(m)} className={`p-5 rounded-[30px] bg-white border-2 flex justify-between items-center transition-all active:scale-95 ${cart.has(m.id!) ? 'border-emerald-500 bg-emerald-50/20' : 'border-transparent shadow-sm'}`}>
                  <div>
                    <h3 className="font-bold text-slate-800 text-lg">{m.name}</h3>
                    <div className="text-[10px] font-black text-emerald-600 mt-1">متاح: {m.stock} <span className="text-slate-300 mx-1">|</span> {m.category}</div>
                  </div>
                  <div className="text-left">
                    <div className="text-xl font-black text-emerald-700">{m.price.toFixed(2)}</div>
                    {cart.has(m.id!) && <div className="bg-emerald-600 text-white px-2 py-0.5 rounded-full text-[10px] font-black mt-1 text-center animate-in zoom-in">{cart.get(m.id!)?.quantity}</div>}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {view === 'inventory' && (
          <div className="space-y-4 animate-in slide-in-from-left duration-300">
            <div className="bg-emerald-600 p-8 rounded-[40px] text-white shadow-2xl relative overflow-hidden">
              <TrendingUp className="absolute -bottom-10 -right-10 w-48 h-48 opacity-10" />
              <div className="relative z-10 flex justify-between items-end">
                <div>
                  <div className="text-4xl font-black tabular-nums">{inventoryValue.cost.toLocaleString()} <span className="text-xs font-normal opacity-70">ج.م</span></div>
                  <div className="text-[10px] font-bold opacity-80 mt-1 uppercase tracking-widest">إجمالي رأس مال المخزن الحالي</div>
                </div>
                <div className="text-left opacity-60">
                   <div className="text-sm font-bold">قيمة البيع المتوقعة:</div>
                   <div className="text-lg font-black">{inventoryValue.sell.toLocaleString()}</div>
                </div>
              </div>
            </div>

            <div className="flex gap-2 overflow-x-auto no-scrollbar">
              {['all', 'low', 'expired', 'stagnant'].map(f => (
                <button key={f} onClick={() => setInvFilter(f as any)} className={`flex-1 py-3 rounded-2xl text-[10px] font-black transition-all ${invFilter === f ? 'bg-slate-800 text-white' : 'bg-white text-slate-400 shadow-sm'}`}>
                  {f === 'all' ? 'الكل' : f === 'low' ? 'نواقص' : f === 'expired' ? 'منتهي' : 'راكد'}
                </button>
              ))}
            </div>

            <div className="bg-white rounded-[35px] shadow-sm border border-slate-100 overflow-hidden">
              <table className="w-full text-right">
                <thead className="bg-slate-50 border-b border-slate-100">
                  <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    <th className="p-4">الصنف</th>
