               <div className="bg-slate-900 p-6 rounded-[35px] shadow-sm text-white">
                  <div className="text-[10px] font-black text-slate-400 uppercase mb-1">إجمالي المبيعات</div>
                  <div className="text-2xl font-black text-white">{stats.sales.toFixed(2)}</div>
               </div>
            </div>

            <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
               <h2 className="text-lg font-black text-slate-800 mb-6 flex items-center gap-2"><ArrowDownRight className="text-emerald-500"/> تقرير الجرد الصافي</h2>
               <div className="space-y-4">
                  <div className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl">
                     <span className="text-sm font-bold text-slate-500">إجمالي المبيعات (كاش + بنك)</span>
                     <span className="font-black text-slate-800">{stats.sales.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl text-rose-500">
                     <span className="text-sm font-bold">إجمالي المصروفات</span>
                     <span className="font-black">-{stats.expenses.toFixed(2)}</span>
