                    </div>
                    <Receipt className="text-slate-200" size={40} />
                 </div>

                 <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 mr-2">مبلغ الخصم</label>
                    <input type="number" className="w-full bg-slate-50 p-4 rounded-2xl font-black outline-none border-2 border-transparent focus:border-emerald-500" value={payData.discount} onChange={e => setPayData({...payData, discount: parseFloat(e.target.value)||0})} />
                 </div>

                 <div className="grid grid-cols-2 gap-3">
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400 mr-2">كاش</label>
                      <input type="number" className="w-full bg-slate-50 p-4 rounded-2xl font-black outline-none border-2 border-emerald-100 focus:border-emerald-500" value={payData.cash} onChange={e => setPayData({...payData, cash: parseFloat(e.target.value)||0})} />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400 mr-2">بنك</label>
                      <input type="number" className="w-full bg-slate-50 p-4 rounded-2xl font-black outline-none border-2 border-blue-100 focus:border-blue-500" value={payData.bank} onChange={e => setPayData({...payData, bank: parseFloat(e.target.value)||0})} />
