                 </div>

                 <button onClick={handleSale} className="w-full bg-emerald-600 text-white py-5 rounded-[22px] font-black text-xl shadow-xl active:scale-95 transition-all mt-4">تأكيد وطباعة</button>
              </div>
           </div>
        </div>
      )}

      {/* Floating Action Button (Add) */}
      <button onClick={() => { setEditingMed(null); setIsEditOpen(true); }} className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-emerald-600 text-white w-18 h-18 rounded-[28px] shadow-2xl flex items-center justify-center active:scale-90 transition-all border-4 border-white z-50">
        <Plus size={32} strokeWidth={3} />
      </button>

      {/* Medicine Modal */}
      {isEditOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4">
           <div className="bg-white w-full max-w-lg rounded-t-[40px] sm:rounded-[45px] shadow-2xl overflow-hidden flex flex-col max-h-[95vh] animate-slide-up">
              <div className="p-8 pb-4 flex justify-between items-center">
                 <h2 className="text-2xl font-black text-slate-800">{editingMed ? 'تعديل صنف' : 'صنف جديد'}</h2>
                 <button onClick={() => setIsEditOpen(false)} className="w-10 h-10 bg-slate-50 text-slate-400 rounded-2xl flex items-center justify-center"><X/></button>
              </div>
              <form onSubmit={async (e) => {
                e.preventDefault();
                const f = e.target as any;
                const data = {
                  name: f.nm.value, barcode: f.bc.value, price: parseFloat(f.pr.value),
                  costPrice: parseFloat(f.cp.value), stock: parseInt(f.st.value),
                  category: f.ct.value, expiryDate: f.ex.value, supplier: f.sp.value,
                  usageCount: editingMed?.usageCount || 0
                };
                if (editingMed?.id) await db.medicines.update(editingMed.id, data);
                else await db.medicines.add(data);
                setIsEditOpen(false); loadData();
              }} className="p-8 pt-4 space-y-4 overflow-y-auto no-scrollbar pb-10">
                 <input name="nm" type="text" placeholder="اسم الصنف" defaultValue={editingMed?.name} required className="w-full bg-slate-50 p-4 rounded-2xl font-bold outline-none border-2 border-transparent focus:border-emerald-500" />
                 <div className="grid grid-cols-2 gap-3">
                   <input name="pr" type="number" step="0.01" placeholder="سعر البيع" defaultValue={editingMed?.price} required className="bg-slate-50 p-4 rounded-2xl font-bold outline-none" />
                   <input name="cp" type="number" step="0.01" placeholder="سعر التكلفة" defaultValue={editingMed?.costPrice} required className="bg-slate-50 p-4 rounded-2xl font-bold outline-none" />
                 </div>
                 <div className="grid grid-cols-2 gap-3">
                   <input name="st" type="number" placeholder="الكمية" defaultValue={editingMed?.stock} required className="bg-slate-50 p-4 rounded-2xl font-bold outline-none" />
                   <input name="ct" type="text" placeholder="الفئة" defaultValue={editingMed?.category} className="bg-slate-50 p-4 rounded-2xl font-bold outline-none" />
                 </div>
                 <div className="grid grid-cols-2 gap-3">
                    <input name="sp" type="text" placeholder="المورد" defaultValue={editingMed?.supplier} className="bg-slate-50 p-4 rounded-2xl font-bold outline-none" />
                    <input name="ex" type="date" defaultValue={editingMed?.expiryDate} className="bg-slate-50 p-4 rounded-2xl font-bold outline-none" />
                 </div>
                 <input name="bc" type="text" placeholder="الباركود (اختياري)" defaultValue={editingMed?.barcode} className="w-full bg-slate-50 p-4 rounded-2xl font-bold outline-none" />
                 <button type="submit" className="w-full bg-emerald-600 text-white py-5 rounded-[22px] font-black shadow-xl active:scale-95 transition-all">حفظ البيانات</button>
                 {editingMed?.id && <button type="button" onClick={async () => { if(confirm('حذف؟')) { await db.medicines.delete(editingMed.id!); setIsEditOpen(false); loadData(); }}} className="w-full bg-rose-50 text-rose-500 py-3 rounded-xl font-bold">حذف الصنف</button>}
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

