                    </div>
                 </div>

                 <input name="bc" type="text" placeholder="الباركود (إن وجد)" defaultValue={editingMed?.barcode} className="w-full bg-slate-50 p-5 rounded-3xl font-bold outline-none border-2 border-transparent focus:border-emerald-500" />

                 <div className="flex gap-3 pt-6">
                   <button type="submit" className="flex-grow bg-emerald-600 text-white py-6 rounded-[35px] font-black text-xl shadow-xl active:scale-95 transition-all">حفظ البيانات</button>
                   {editingMed?.id && (
                     <button type="button" onClick={async () => { if(confirm('حذف هذا المنتج نهائياً من المخزن؟')) { await db.medicines.delete(editingMed.id!); setIsEditOpen(false); loadData(); }}} className="bg-rose-50 text-rose-500 px-8 rounded-[35px] hover:bg-rose-100 transition-all shadow-sm"><Trash2 size={24}/></button>
                   )}
                 </div>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

export interface Medicine {
  id?: number;
  name: string;
  barcode: string;
  price: number;
  costPrice: number;
  stock: number;
  category: string;
  expiryDate: string;
  addedDate: string; // تاريخ الإضافة التلقائي
  supplier: string;
  usageCount: number;
  lastSold?: number;
}

export interface Expense {
  id?: number;
  amount: number;
  type: string;
  description: string;
  timestamp: number;
}

export interface Customer {
  id?: number;
  name: string;
}

export interface Sale {
  id?: number;
  totalAmount: number;
  discount: number;
  netAmount: number;
  cashAmount: number;
  bankAmount: number;
  debtAmount: number;
  bankTrxId?: string;
  customerName?: string;
  totalCost: number;
  profit: number;
  timestamp: number;
  itemsJson: string; 
  isReturned?: boolean;
}

export interface CartItem {
  medicine: Medicine;
  quantity: number;
}

export type ViewType = 'pos' | 'accounting' | 'inventory' | 'expenses';

import Dexie, { type Table } from 'dexie';
import { Medicine, Sale, Expense, Customer } from './types';

export class RahaDB extends Dexie {
  medicines!: Table<Medicine, number>;
  sales!: Table<Sale, number>;
  expenses!: Table<Expense, number>;
  customers!: Table<Customer, number>;

  constructor() {
    super('RahaDB');
    this.version(6).stores({
      medicines: '++id, name, barcode, category, supplier, addedDate, expiryDate, usageCount',
      sales: '++id, timestamp, customerName, isReturned',
      expenses: '++id, timestamp, type',
      customers: '++id, name'
    });
  }
}

export const db = new RahaDB();

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { 
  Search, Plus, Package, BarChart3, ShoppingCart, X, Trash2, 
  CheckCircle2, TrendingUp, AlertCircle, Coins, 
  CreditCard, Wallet, UserMinus, ShoppingBag, 
  ArrowRight, Minus, Edit3, Truck, Receipt, Calendar, 
  RotateCcw, Download, Filter, ArrowDownRight, Layers, Bell, Info, ArrowUpRight
} from 'lucide-react';
import { db } from './db';
import { Medicine, ViewType, Sale, CartItem, Expense, Customer } from './types';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('pos');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [salesHistory, setSalesHistory] = useState<Sale[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);

  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState('الكل');

  // Inventory Advanced Filters
  const [stockFilter, setStockFilter] = useState<'all' | 'low' | 'out'>('all');
  const [expiryFilter, setExpiryFilter] = useState<'all' | 'expired' | 'near'>('all');
  const [supplierFilter, setSupplierFilter] = useState('الكل');

  // Finance & Expense Filters
  const [payFilter, setPayFilter] = useState<'all' | 'cash' | 'bank' | 'debt'>('all');
  const [expenseDate, setExpenseDate] = useState(new Date().toISOString().split('T')[0]);

  // UI State
  const [cart, setCart] = useState<Map<number, CartItem>>(new Map());
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [isEditOpen, setIsEditOpen] = useState(false);
  const [editingMed, setEditingMed] = useState<Medicine | null>(null);
  const [payData, setPayData] = useState({ discount: '', cash: '', bank: '', debt: '', trx: '', cust: '' });

  const loadData = useCallback(async () => {
    const [m, s, e, c] = await Promise.all([
      db.medicines.toArray(),
      db.sales.orderBy('timestamp').reverse().toArray(),
      db.expenses.orderBy('timestamp').reverse().toArray(),
      db.customers.toArray()
    ]);
    setMedicines(m);
    setSalesHistory(s);
    setExpenses(e);
    setCustomers(c);
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  // Auto-Crawling Logic: Dynamic Categories
  const categories = useMemo(() => {
    const cats = Array.from(new Set(medicines.map(m => m.category || 'عام')));
    const usage = medicines.reduce((acc, m) => {
      acc[m.category] = (acc[m.category] || 0) + (m.usageCount || 0);
      return acc;
    }, {} as Record<string, number>);
    return ['الكل', ...cats.sort((a, b) => (usage[b] || 0) - (usage[a] || 0))];
  }, [medicines]);

  const suppliers = useMemo(() => ['الكل', ...Array.from(new Set(medicines.map(m => m.supplier))).filter(Boolean)], [medicines]);
  const expenseTypes = useMemo(() => Array.from(new Set(expenses.map(e => e.type))), [expenses]);

  // Alerts Logic
  const alerts = useMemo(() => {
    const now = Date.now();
    const low = medicines.filter(m => m.stock > 0 && m.stock <= 5).length;
    const expired = medicines.filter(m => new Date(m.expiryDate).getTime() < now).length;
    const near = medicines.filter(m => {
      const diff = new Date(m.expiryDate).getTime() - now;
      return diff > 0 && diff < (30 * 24 * 60 * 60 * 1000);
    }).length;
    return { low, expired, near, total: low + expired + near };
  }, [medicines]);

  // Filtering Logic
  const posItems = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    return medicines
      .filter(m => (m.name.toLowerCase().includes(q) || m.barcode.includes(q)) && (activeCategory === 'الكل' || m.category === activeCategory))
      .sort((a, b) => (b.usageCount || 0) - (a.usageCount || 0));
  }, [medicines, searchQuery, activeCategory]);

  const filteredInventory = useMemo(() => {
    const now = Date.now();
    return medicines.filter(m => {
      let matchesStock = true;
      if (stockFilter === 'low') matchesStock = m.stock > 0 && m.stock <= 5;
      else if (stockFilter === 'out') matchesStock = m.stock <= 0;

      let matchesExpiry = true;
      if (expiryFilter === 'expired') matchesExpiry = new Date(m.expiryDate).getTime() < now;
      else if (expiryFilter === 'near') {
        const diff = new Date(m.expiryDate).getTime() - now;
        matchesExpiry = diff > 0 && diff < (30 * 24 * 60 * 60 * 1000);
      }

      const matchesSupplier = supplierFilter === 'الكل' || m.supplier === supplierFilter;
      const matchesCategory = activeCategory === 'الكل' || m.category === activeCategory;

      return matchesStock && matchesExpiry && matchesSupplier && matchesCategory;
    });
  }, [medicines, stockFilter, expiryFilter, supplierFilter, activeCategory]);

  const inventoryValue = useMemo(() => {
    return filteredInventory.reduce((acc, m) => {
      acc.cost += m.stock * m.costPrice;
      acc.sell += m.stock * m.price;
      return acc;
    }, { cost: 0, sell: 0 });
  }, [filteredInventory]);

  const financeStats = useMemo(() => {
    const filtered = salesHistory.filter(s => {
      if (payFilter === 'all') return true;
      if (payFilter === 'cash') return s.cashAmount > 0 && s.bankAmount === 0 && s.debtAmount === 0;
      if (payFilter === 'bank') return s.bankAmount > 0;
      if (payFilter === 'debt') return s.debtAmount > 0;
      return true;
    });

    const totals = filtered.reduce((acc, s) => {
      if (!s.isReturned) {
        acc.sales += s.netAmount;
        acc.costs += s.totalCost;
        acc.profit += s.profit;
        acc.cash += s.cashAmount;
        acc.bank += s.bankAmount;
        acc.debt += s.debtAmount;
      }
      return acc;
    }, { sales: 0, costs: 0, profit: 0, cash: 0, bank: 0, debt: 0 });

    return { ...totals, list: filtered };
  }, [salesHistory, payFilter]);

  const filteredExpenses = useMemo(() => {
    return expenses.filter(e => new Date(e.timestamp).toISOString().split('T')[0] === expenseDate);
  }, [expenses, expenseDate]);

  // Cart Management
  const addToCart = (m: Medicine) => {
    if (m.stock <= 0) return;
    const newCart = new Map(cart);
    const item = newCart.get(m.id!) || { medicine: m, quantity: 0 };
    if (item.quantity < m.stock) {
      newCart.set(m.id!, { ...item, quantity: item.quantity + 1 });
      setCart(newCart);
    }
  };

  const removeFromCart = (id: number) => {
    const newCart = new Map(cart);
    const item = newCart.get(id);
    if (!item) return;
    if (item.quantity > 1) newCart.set(id, { ...item, quantity: item.quantity - 1 });
    else newCart.delete(id);
    setCart(newCart);
  };

  // Finalize Sale
  const handleSale = async () => {
    const cartTotal = Array.from(cart.values()).reduce((s, i) => s + (i.medicine.price * i.quantity), 0);
    const net = cartTotal - (parseFloat(payData.discount) || 0);
    const cash = parseFloat(payData.cash) || 0;
    const bank = parseFloat(payData.bank) || 0;
    const debt = parseFloat(payData.debt) || 0;

    if (Math.abs((cash + bank + debt) - net) > 0.1) {
      alert("خطأ: المبالغ الموزعة لا تطابق الصافي المطلوب."); return;
    }

    await db.transaction('rw', [db.medicines, db.sales, db.customers], async () => {
      const items = Array.from(cart.values());
      const totalCost = items.reduce((s, i) => s + (i.medicine.costPrice * i.quantity), 0);

      for (const item of items) {
        await db.medicines.update(item.medicine.id!, {
          stock: item.medicine.stock - item.quantity,
          usageCount: (item.medicine.usageCount || 0) + item.quantity,
          lastSold: Date.now()
        });
      }

      if (payData.cust) {
        const exists = await db.customers.where('name').equals(payData.cust).first();
        if (!exists) await db.customers.add({ name: payData.cust });
      }

      await db.sales.add({
        totalAmount: cartTotal,
        discount: parseFloat(payData.discount) || 0,
        netAmount: net,
        cashAmount: cash,
        bankAmount: bank,
        debtAmount: debt,
        bankTrxId: payData.trx,
        customerName: payData.cust,
        totalCost,
        profit: net - totalCost,
        timestamp: Date.now(),
        itemsJson: JSON.stringify(items)
      });
    });

    setCart(new Map());
    setIsCheckoutOpen(false);
    loadData();
  };

  const handleReturn = async (sale: Sale) => {
    if (!confirm("تأكيد إرجاع هذه الطلبية للمخزن؟")) return;
    await db.transaction('rw', [db.medicines, db.sales], async () => {
      const items = JSON.parse(sale.itemsJson);
      for (const item of items) {
        const m = await db.medicines.get(item.medicine.id);
        if (m) await db.medicines.update(m.id!, { stock: m.stock + item.quantity });
      }
      await db.sales.update(sale.id!, { isReturned: true });
    });
    loadData();
  };

  const inlineUpdate = async (id: number, field: string, val: string) => {
    const n = parseFloat(val);
    if (!isNaN(n)) {
      await db.medicines.update(id, { [field]: n });
      loadData();
    }
  };

  return (
    <div className="flex flex-col h-screen bg-[#F8FAFC] text-slate-900 overflow-hidden font-medium">
      {/* Dynamic Header */}
      <header className="bg-white px-6 pt-10 pb-4 shadow-sm z-30 border-b border-slate-100 shrink-0">
        <div className="flex justify-between items-center mb-6">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center text-white shadow-lg">
                <Layers size={20} />
             </div>
             <div>
                <h1 className="text-xl font-black text-slate-800">راحة <span className="text-emerald-600">PRO</span></h1>
             </div>
          </div>
          <div className="flex gap-2">
            {alerts.total > 0 && (
               <div className="flex items-center gap-2 bg-rose-50 text-rose-600 px-3 py-1.5 rounded-xl text-[10px] font-black animate-pulse cursor-help" title="تنبيهات المخزن">
                  <Bell size={14} /> {alerts.total} تنبيه
               </div>
            )}
            <button onClick={() => { setEditingMed(null); setIsEditOpen(true); }} className="p-2.5 bg-emerald-50 text-emerald-600 rounded-xl"><Plus size={20} /></button>
          </div>
        </div>

        <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
          {['pos', 'inventory', 'accounting', 'expenses'].map((v) => (
            <button key={v} onClick={() => { setView(v as ViewType); setActiveCategory('الكل'); }} className={`px-6 py-2.5 rounded-2xl text-xs font-black whitespace-nowrap transition-all ${view === v ? 'bg-emerald-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400'}`}>
              {v === 'pos' ? 'نقطة البيع' : v === 'inventory' ? 'المخزن' : v === 'accounting' ? 'التقارير' : 'المنصرفات'}
            </button>
          ))}
        </div>
      </header>

      {/* Main Container */}
      <main className="flex-grow overflow-y-auto p-4 pb-48 no-scrollbar">
        {view === 'pos' && (
          <div className="animate-in fade-in duration-300">
            <div className="relative mb-4">
              <input type="text" placeholder="بحث باسم الصنف أو الباركود..." className="w-full bg-white rounded-3xl py-4 pr-12 pl-4 text-lg font-bold shadow-sm border-2 border-transparent focus:border-emerald-500 outline-none transition-all" value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
              <Search className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300" />
            </div>

            <div className="flex gap-2 overflow-x-auto no-scrollbar mb-4">
              {categories.map(c => (
                <button key={c} onClick={() => setActiveCategory(c)} className={`px-5 py-2.5 rounded-2xl text-[10px] font-black transition-all ${activeCategory === c ? 'bg-emerald-600 text-white shadow-md' : 'bg-white text-slate-400 shadow-sm border border-slate-100'}`}>{c}</button>
              ))}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
              {posItems.map(m => (
                <div key={m.id} onClick={() => addToCart(m)} className={`p-5 rounded-[35px] bg-white border-2 flex justify-between items-center transition-all active:scale-95 ${cart.has(m.id!) ? 'border-emerald-500 bg-emerald-50/20' : 'border-transparent shadow-sm'}`}>
                  <div>
                    <h3 className="font-bold text-slate-800 text-lg leading-tight">{m.name}</h3>
                    <div className="text-[10px] font-black mt-1 flex items-center gap-2">
                       <span className={`${m.stock <= 5 ? 'text-rose-500' : 'text-emerald-600'}`}>متاح: {m.stock}</span>
                       <span className="text-slate-200">|</span>
                       <span className="text-slate-400">{m.category}</span>
                    </div>
                  </div>
                  <div className="text-left shrink-0">
                    <div className="text-xl font-black text-emerald-700">{m.price.toFixed(2)}</div>
                    {cart.has(m.id!) && (
                      <div className="flex items-center gap-2 mt-2" onClick={e => e.stopPropagation()}>
                        <button onClick={() => removeFromCart(m.id!)} className="w-8 h-8 rounded-xl bg-rose-50 text-rose-500 flex items-center justify-center"><Minus size={14}/></button>
                        <span className="text-sm font-black text-slate-700">{cart.get(m.id!)?.quantity}</span>
                        <button onClick={() => addToCart(m)} className="w-8 h-8 rounded-xl bg-emerald-600 text-white flex items-center justify-center"><Plus size={14}/></button>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {view === 'inventory' && (
          <div className="space-y-4 animate-in slide-in-from-left duration-300">
            {/* Top Value Summary */}
            <div className="grid grid-cols-2 gap-3 mb-4">
               <div className="bg-emerald-600 p-6 rounded-[35px] text-white shadow-xl shadow-emerald-100">
                  <div className="text-[9px] font-black opacity-70 uppercase mb-1">قيمة المخزون (بيع)</div>
                  <div className="text-2xl font-black tabular-nums">{inventoryValue.sell.toLocaleString()}</div>
               </div>
               <div className="bg-slate-800 p-6 rounded-[35px] text-white shadow-xl">
                  <div className="text-[9px] font-black opacity-70 uppercase mb-1">رأس المال (تكلفة)</div>
                  <div className="text-2xl font-black tabular-nums">{inventoryValue.cost.toLocaleString()}</div>
               </div>
            </div>

            <div className="bg-white p-5 rounded-[35px] shadow-sm border border-slate-100 space-y-4">
              <div className="flex flex-wrap gap-2">
                <select className="bg-slate-50 p-3 rounded-2xl text-[10px] font-black border-none outline-none" value={stockFilter} onChange={e => setStockFilter(e.target.value as any)}>
                  <option value="all">كل المخزون</option>
                  <option value="low">النواقص (5 فأقل)</option>
                  <option value="out">نفد المخزون</option>
                </select>
                <select className="bg-slate-50 p-3 rounded-2xl text-[10px] font-black border-none outline-none" value={expiryFilter} onChange={e => setExpiryFilter(e.target.value as any)}>
                  <option value="all">كل التواريخ</option>
                  <option value="expired">منتهي الصلاحية</option>
                  <option value="near">قريب الانتهاء</option>
                </select>
                <select className="bg-slate-50 p-3 rounded-2xl text-[10px] font-black border-none outline-none" value={supplierFilter} onChange={e => setSupplierFilter(e.target.value)}>
                   {suppliers.map(s => <option key={s} value={s}>{s}</option>)}
                </select>
                <select className="bg-slate-50 p-3 rounded-2xl text-[10px] font-black border-none outline-none" value={activeCategory} onChange={e => setActiveCategory(e.target.value)}>
                   {categories.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>

              <div className="overflow-x-auto no-scrollbar">
                <table className="w-full text-right text-xs">
                  <thead className="bg-slate-50 text-slate-400 font-black uppercase tracking-widest border-b border-slate-100">
                    <tr>
                      <th className="p-4">الصنف</th>
                      <th className="p-4">الكمية</th>
                      <th className="p-4">الأسعار</th>
                      <th className="p-4">الانتهاء</th>
                      <th className="p-4"></th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50 font-bold">
                    {filteredInventory.map(m => (
                      <tr key={m.id} className="hover:bg-slate-50 transition-colors">
                        <td className="p-4">
                           <div className="text-slate-800 text-sm font-black">{m.name}</div>
                           <div className="text-[9px] text-slate-300">{m.supplier || 'بدون مورد'}</div>
                        </td>
                        <td className="p-4">
                           <span className={`px-2 py-1 rounded-lg ${m.stock <= 5 ? 'bg-rose-50 text-rose-500' : 'bg-emerald-50 text-emerald-600'}`}>{m.stock}</span>
                        </td>
                        <td className="p-4">
                           <div className="flex flex-col gap-1">
                              <input type="number" onFocus={e => e.target.select()} className="w-16 bg-emerald-50 text-emerald-700 font-black rounded px-1 outline-none" defaultValue={m.price} onBlur={e => inlineUpdate(m.id!, 'price', e.target.value)} />
                              <input type="number" onFocus={e => e.target.select()} className="w-16 bg-slate-50 text-slate-400 font-bold rounded px-1 outline-none" defaultValue={m.costPrice} onBlur={e => inlineUpdate(m.id!, 'costPrice', e.target.value)} />
                           </div>
                        </td>
                        <td className="p-4 text-slate-400 whitespace-nowrap">{m.expiryDate}</td>
                        <td className="p-4">
                           <button onClick={() => { setEditingMed(m); setIsEditOpen(true); }} className="p-2 text-slate-200 hover:text-emerald-500"><Edit3 size={16}/></button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}

        {view === 'accounting' && (
          <div className="space-y-6 animate-in zoom-in-95 duration-300">
             {/* Financial Dashboard */}
             <div className="bg-slate-900 p-8 rounded-[45px] text-white shadow-2xl relative overflow-hidden">
                <div className="relative z-10 space-y-6">
                   <div className="flex justify-between items-start">
                      <div>
                         <span className="text-[10px] font-black text-emerald-400 uppercase tracking-widest">صافي الأرباح (بعد المنصرفات)</span>
                         <h2 className="text-4xl font-black tabular-nums mt-1">{(financeStats.profit - stats.expenses).toFixed(2)} <span className="text-xs font-normal opacity-50">ج.م</span></h2>
                      </div>
                      <div className="p-3 bg-white/10 rounded-2xl text-emerald-400"><TrendingUp size={28}/></div>
                   </div>

                   <div className="grid grid-cols-2 gap-6 border-t border-white/10 pt-6">
                      <div>
                         <span className="text-[10px] font-bold text-slate-400 uppercase">البيع الكلي</span>
                         <div className="text-xl font-black">{financeStats.sales.toFixed(2)}</div>
                      </div>
                      <div>
                         <span className="text-[10px] font-bold text-slate-400 uppercase">ربح المبيعات</span>
                         <div className="text-xl font-black text-emerald-400">{financeStats.profit.toFixed(2)}</div>
                      </div>
                   </div>

                   <div className="flex gap-2 overflow-x-auto no-scrollbar pt-2">
                      <div className="bg-white/5 px-4 py-2 rounded-xl text-center flex-1">
                         <div className="text-[8px] font-black text-emerald-400 uppercase">كاش</div>
                         <div className="text-sm font-black">{financeStats.cash.toFixed(2)}</div>
                      </div>
                      <div className="bg-white/5 px-4 py-2 rounded-xl text-center flex-1">
                         <div className="text-[8px] font-black text-blue-400 uppercase">بنكك</div>
                         <div className="text-sm font-black">{financeStats.bank.toFixed(2)}</div>
                      </div>
                      <div className="bg-white/5 px-4 py-2 rounded-xl text-center flex-1 text-amber-400">
                         <div className="text-[8px] font-black uppercase">مديونية</div>
                         <div className="text-sm font-black">{financeStats.debt.toFixed(2)}</div>
                      </div>
                   </div>
                </div>
             </div>

             <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
                {['all', 'cash', 'bank', 'debt'].map(f => (
                   <button key={f} onClick={() => setPayFilter(f as any)} className={`px-5 py-2.5 rounded-2xl text-[10px] font-black transition-all ${payFilter === f ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white text-slate-400 border border-slate-100'}`}>
