                      <div>
                         <span className="text-[10px] font-black text-emerald-400 uppercase tracking-widest">صافي الأرباح (بعد المنصرفات)</span>
                         {/* Corrected logic to use totalExpensesSum and fixed the 'stats' variable error */}
                         <h2 className="text-4xl font-black tabular-nums mt-1">{(financeStats.profit - totalExpensesSum).toFixed(2)} <span className="text-xs font-normal opacity-50">ج.م</span></h2>
                      </div>
                      <div className="p-3 bg-white/10 rounded-2xl text-emerald-400"><TrendingUp size={28}/></div>
                   </div>

                   <div className="grid grid-cols-2 gap-6 border-t border-white/10 pt-6">
                      <div>
                         <span className="text-[10px] font-bold text-slate-400 uppercase">البيع الكلي</span>
                         <div className="text-xl font-black">{financeStats.sales.toFixed(2)}</div>
                      </div>
                      <div>
                         <span className="text-[10px] font-bold text-slate-400 uppercase">ربح المبيعات</span>
                         <div className="text-xl font-black text-emerald-400">{financeStats.profit.toFixed(2)}</div>
                      </div>
                   </div>

                   <div className="flex gap-2 overflow-x-auto no-scrollbar pt-2">
                      <div className="bg-white/5 px-4 py-2 rounded-xl text-center flex-1">
                         <div className="text-[8px] font-black text-emerald-400 uppercase">كاش</div>
                         <div className="text-sm font-black">{financeStats.cash.toFixed(2)}</div>
                      </div>
                      <div className="bg-white/5 px-4 py-2 rounded-xl text-center flex-1">
                         <div className="text-[8px] font-black text-blue-400 uppercase">بنكك</div>
                         <div className="text-sm font-black">{financeStats.bank.toFixed(2)}</div>
                      </div>
                      <div className="bg-white/5 px-4 py-2 rounded-xl text-center flex-1 text-amber-400">
                         <div className="text-[8px] font-black uppercase">مديونية</div>
                         <div className="text-sm font-black">{financeStats.debt.toFixed(2)}</div>
                      </div>
                   </div>
                </div>
             </div>

             <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
                {['all', 'cash', 'bank', 'debt'].map(f => (
                   <button key={f} onClick={() => setPayFilter(f as any)} className={`px-5 py-2.5 rounded-2xl text-[10px] font-black transition-all ${payFilter === f ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white text-slate-400 border border-slate-100'}`}>
                      {f === 'all' ? 'الكل' : f === 'cash' ? 'كاش فقط' : f === 'bank' ? 'بنكك' : 'مديونيات'}
                   </button>
                ))}
             </div>

             <div className="space-y-3">
                {financeStats.list.map(s => (
                   <div key={s.id} className={`p-6 rounded-[35px] bg-white border border-slate-100 shadow-sm flex flex-col gap-4 ${s.isReturned ? 'opacity-40 grayscale' : ''}`}>
                      <div className="flex justify-between items-start">
