const CACHE_NAME = 'raha-pro-cache-v3';
const OFFLINE_URL = '/index.html';

const ASSETS_TO_CACHE = [
  '/',
  '/index.html',
  '/manifest.json',
  '/index.tsx',
  'https://cdn.tailwindcss.com',
  'https://fonts.googleapis.com/css2?family=Noto+Sans+Arabic:wght@400;500;700;900&display=swap',
  'https://esm.sh/lucide-react@^0.562.0',
  'https://esm.sh/react@^19.2.3',
  'https://esm.sh/react-dom@^19.2.3/',
  'https://esm.sh/dexie@^4.2.1'
];

// تثبيت الـ Service Worker وحفظ الملفات الأساسية
self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      console.log('Raha Pro: Caching shell assets');
      return cache.addAll(ASSETS_TO_CACHE);
    })
  );
  self.skipWaiting();
});

// تفعيل وتحديث الكاش القديم
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cacheName) => {
          if (cacheName !== CACHE_NAME) {
            console.log('Raha Pro: Deleting old cache', cacheName);
            return caches.delete(cacheName);
          }
        })
      );
    })
  );
  self.clients.claim();
});

// استراتيجية Cache-First للعمل أوفلاين 100%
self.addEventListener('fetch', (event) => {
  // لا نقوم بتخزين طلبات الـ API الخارجية إذا وجدت (غير مستخدمة حالياً لأننا نعتمد على IndexedDB)
  if (event.request.mode === 'navigate') {
    event.respondWith(
      fetch(event.request).catch(() => {
        return caches.match(OFFLINE_URL);
      })
    );
    return;
  }

  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request).then((fetchResponse) => {
        // تخزين أي ملفات جديدة يتم طلبها في الكاش لزيادة سرعة الأداء لاحقاً
        return caches.open(CACHE_NAME).then((cache) => {
          if (event.request.url.startsWith('http')) {
             cache.put(event.request, fetchResponse.clone());
          }
          return fetchResponse;
        });
      });
    }).catch(() => {
      if (event.request.destination === 'image') {
        return caches.match('https://cdn-icons-png.flaticon.com/512/4320/4320337.png');
      }
    })
  );
});

import { Dexie } from 'dexie';
import type { Table } from 'dexie';
import { Medicine, Sale, Expense, Customer, AppNotification } from './types';

// Fix: Import Dexie as a named export. Default imports can sometimes lead to incorrect type resolution for inherited class methods like version() and transaction().
export class RahaDB extends Dexie {
  medicines!: Table<Medicine, number>;
  sales!: Table<Sale, number>;
  expenses!: Table<Expense, number>;
  customers!: Table<Customer, number>;
  notifications!: Table<AppNotification, number>;

  constructor() {
    super('RahaDB');
    // Define database schema version and tables
    // The version method is inherited from the Dexie base class.
    this.version(8).stores({
      medicines: '++id, name, barcode, category, supplier, addedDate, expiryDate, usageCount, lastSold',
      sales: '++id, timestamp, customerName, isReturned',
      expenses: '++id, timestamp, type',
      customers: '++id, name',
      notifications: '++id, timestamp'
    });
  }
}

export const db = new RahaDB();

